window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["z"]={"Zbigniew": "<b>Zbigniew</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Złożone jest z dwóch członów: <i>Zby-</i> („zbyć, zbyć się, pozbyć się”) i <i>-gniew</i> („gniew”). Mogło oznaczać „tego, który się zbył (pozbył) gniewu”. Właściwie powinno ono brzmieć <b>Zbygniew</b>, a Zbigniew to wynik zniekształcenia, które nastąpiło przy odczycie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a> przez pierwszych badaczy. W Polsce imię to po raz pierwszy odnotowano jako <i>Zbygniew</i>. Do końca <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a> imię Zbygniew zanotowano u około 1000 osób.", "Zdzisław": "<b>Zdzisław</b>, <i><b>Zdziesław</b></i> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z dwóch członów: <i>Zdzie (Zdzi-)</i> (\"uczynić, zdziałać, zrobić\") i <i>-sław</i> (\"sława\"). Zanotowane w dokumentach z roku 1198.", "Zygmunt": "<b>Zygmunt</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie oraz <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Składa się ze słów: <i>sigu</i> oznaczającego „zwycięstwo” i <i>mund</i> lub <i>munt</i>, „opieka”, „tarcza”. Można je zatem tłumaczyć jako „obrona przez zwycięstwo”.", "Zenon": "<b>Zenon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Powstało jako forma skrócona greckich imion złożonych typu <i>Zenodoros</i>, <i>Zenodotos</i>, oznaczających \"dar <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a>\".", "Zygfryd": "<b>Zygfryd</b>, <b>Sygurd</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>sigu</i> i <i>fridu</i> oznaczających <i>zwycięstwo</i> i <i>opieka</i>, jako ten, który zapewnia bezpieczeństwo swym podopiecznym. Imię to było znane w Polsce od średniowiecza, m.in. w formach: Zebrzyd, Zybrzyd, Zewrzyd, Zywrzyd. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Zygfryda\" target=\"_blank\" rel=\"noopener noreferrer\">Zygfryda</a>.", "Ziemowit": "<b>Ziemowit</b> – zniekształcona forma <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Siemowit_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Siemowit</a> oznaczającego „głowę rodu”.", "Zakhar": "<p>Zakhar (rosyjski: Захар) to imię, wschodnio-słowiańska forma biblijnej nazwy Zachariasz lub Zachary. Do wybitnych osób z nazwiskiem należą: Zakhar Arzamastsev (ur. 1992), rosyjski hokejista na lodzie Zakhar Bron (ur. 1947), rosyjskie skrzypcze i pedagog skrzypce pochodzenia żydowskiego Zakhar Chernyshyov (1722-1784), rosyjski marszałek pola odpowiedzialny za Kolegium Wojny w latach 1763-1774 Zakhar Dubensky (ur. 1978), piłkarz stowarzyszenia...</p>", "Zbysław": "<b>Zbysław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z dwóch członów: <i>Zby-</i> („zbyć się, pozbyć się”) i <i>-sław</i>.", "Zachary": "<p>Zachariasz to imię męskie, odmiana imienia Zachariasza - imienia kilku biblijskich postaci.</p>", "Zbyszek": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zbigniew</b>.</p><b>Zbigniew</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Złożone jest z dwóch członów: <i>Zby-</i> („zbyć, zbyć się, pozbyć się”) i <i>-gniew</i> („gniew”). Mogło oznaczać „tego, który się zbył (pozbył) gniewu”. Właściwie powinno ono brzmieć <b>Zbygniew</b>, a Zbigniew to wynik zniekształcenia, które nastąpiło przy odczycie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a> przez pierwszych badaczy. W Polsce imię to po raz pierwszy odnotowano jako <i>Zbygniew</i>. Do końca <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a> imię Zbygniew zanotowano u około 1000 osób.", "Zachariasz": "<b>Zachariasz</b>, <b>Zachary</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> słowa זְכַרְיָה (<i>zecharja</i>) znaczącego „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> pamięta”. Forma Zachary była nadawana bardzo rzadko, ale występowała w polszczyźnie co najmniej od <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII wieku</a>. Kościół katolicki zna 11 świętych o tym imieniu; są to w większości prorocy z czasów <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">starotestamentowych</a>. Jeden z nich jest autorem biblijnej <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Zachariasza\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Zachariasza</a>.", "Zaza": "<p>⁇ Zaza ⁇ (stylizowany pod maskulą) - single amerykańskiego rapera 6ix9ine, wydany 19 lutego 2021 r. r. równocześnie z klipem muzycznym.</p>", "Zbyszko": "<b>Zbyszko</b> – zdrobnienie od imion <a href=\"https://pl.wikipedia.org/wiki/Zbigniew\" target=\"_blank\" rel=\"noopener noreferrer\">Zbygniew</a>, <a href=\"https://pl.wikipedia.org/wiki/Zbys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Zbysław</a>, <a href=\"https://pl.wikipedia.org/wiki/Zbylut\" target=\"_blank\" rel=\"noopener noreferrer\">Zbylut</a> i <a href=\"https://pl.wikipedia.org/wiki/Zbywoj\" target=\"_blank\" rel=\"noopener noreferrer\">Zbywoj</a>. Obecnie bywa nadawane jako samodzielne imię.", "Zenobiusz": "<b>Zenobiusz</b>, <b>Zenobi</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, złożone z członów <i>Dzeno-</i> (<a href=\"https://pl.wikipedia.org/wiki/Homer\" target=\"_blank\" rel=\"noopener noreferrer\">homerycka</a> forma imienia <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a>) i <i>bios</i> („życie”). Wymowa <i>Zenobios</i>, zamiast pierwotnej <i>Dzenobios</i>, pochodzi z czasów rzymskich.", "Zinovii": "<p>Zinovy lub Zinovi (rosyjski: Зиновий, romanizowany: Zinoviy; ukraiński: Зиновій, romanized: Zynoviy) to wschodnio-słowiańskie imię męskie pochodzące od Zenobios. Zmiany kobiece: rosyjski: Zinovia, ukraiński: Zynoviia (por.</p>", "Zoran": "<b>Zoran</b> (<a href=\"https://pl.wikipedia.org/wiki/Cyrylica_serbska\" target=\"_blank\" rel=\"noopener noreferrer\">cyrylica serbska</a>: Зоран) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">południowosłowiańskie</a>, wywodzące się od słowa <i>zora</i> czyli „zorza, świt, jutrznia”.", "Zoltán": "Zoltán poślubił nieznaną z imienia księżniczkę <a href=\"https://pl.wikipedia.org/wiki/Morawy\" target=\"_blank\" rel=\"noopener noreferrer\">morawską</a>, przypuszczalnie córkę <a href=\"https://pl.wikipedia.org/wiki/Mojmir_II\" target=\"_blank\" rel=\"noopener noreferrer\">Mojmira II</a>.", "Zafar": "<p>Zafar (w rosyjskiej transkrypcji - Zafar, arab. ظفر - Triumf) - irańska skrzydłowa rakieta przeciw okrętom, z aktywnymi głowicami radolocation samowyznawczymi i niskowy profil lotu.</p>", "Zachar": "<p>Zachar to zarówno imię, jak i nazwisko pochodzenia żydowskiego. Znani ludzie z nazwiska to: Zachar Šybieka (ur. 1948), białoruski historyk Imre Zachár (1890-1954), węgierski piłkarz polo wodnego Jacob Zachar (ur. 1986), amerykański aktor Ján Zachar (r. 1936), szłowacki trener piłki nożnej Karol Zachar (1918-2003), słowacki dyrektor</p>", "Zawisza": "<b>Zawisza</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">cz.</a>&#160;<em>Záviš</em>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a>&#160;Zaviša) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">starosłowiańskie imię</a> męskie. Wywodzi się od słowa oznaczającego „zazdrosny o sławę”.", "Zoltan": "Zoltán poślubił nieznaną z imienia księżniczkę <a href=\"https://pl.wikipedia.org/wiki/Morawy\" target=\"_blank\" rel=\"noopener noreferrer\">morawską</a>, przypuszczalnie córkę <a href=\"https://pl.wikipedia.org/wiki/Mojmir_II\" target=\"_blank\" rel=\"noopener noreferrer\">Mojmira II</a>.", "Zinoviy": "<p>Zinovy lub Zinovi (rosyjski: Зиновий, romanizowany: Zinoviy; ukraiński: Зиновій, romanized: Zynoviy) to wschodnio-słowiańskie imię męskie pochodzące od Zenobios. Zmiany kobiece: rosyjski: Zinovia, ukraiński: Zynoviia (por.</p>", "Zbisław": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zbysław</b>.</p><b>Zbysław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z dwóch członów: <i>Zby-</i> („zbyć się, pozbyć się”) i <i>-sław</i>.", "Zefiryn": "<b>Zefiryn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Jest to imię <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99_teoforyczne\" target=\"_blank\" rel=\"noopener noreferrer\">teoforyczne</a>, utworzone za pomocą sufiksu <i>-inus</i> od imienia greckiego boga wiatru zachodniego, <a href=\"https://pl.wikipedia.org/wiki/Zefir\" target=\"_blank\" rel=\"noopener noreferrer\">Zefira</a> (gr. <i>Zéphyros</i>).", "Zahid": "<p>Zahid to męskie imię i nazwisko lub nazwisko, szczególnie popularne w kilku krajach Bliskiego Wschodu i Azji. Jego korzenie są w języku arabskim.</p>", "Ziad": "<p>Ziad (arabski: زياد, romanized: Ziād) to arabskie imię i nazwisko.</p>", "Zlatan": "<b>Zlatan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a>&#160;Златан) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>. Popularne jest zwłaszcza wśród narodów <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie_po%C5%82udniowi\" target=\"_blank\" rel=\"noopener noreferrer\">południowosłowiańskich</a>; <a href=\"https://pl.wikipedia.org/wiki/Chorwaci\" target=\"_blank\" rel=\"noopener noreferrer\">Chorwatów</a>, <a href=\"https://pl.wikipedia.org/wiki/Serbowie\" target=\"_blank\" rel=\"noopener noreferrer\">Serbów</a>, <a href=\"https://pl.wikipedia.org/wiki/Boszniacy\" target=\"_blank\" rel=\"noopener noreferrer\">Boszniaków</a>, <a href=\"https://pl.wikipedia.org/wiki/Macedo%C5%84czycy\" target=\"_blank\" rel=\"noopener noreferrer\">Macedończyków</a>, <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garzy\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgarów</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owe%C5%84cy\" target=\"_blank\" rel=\"noopener noreferrer\">Sloweńców</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_po%C5%82udniowos%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">południowosłowiańskiego</a> słowa <i>zlato</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a>&#160;злато) oznaczającego w języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a> <i><a href=\"https://pl.wikipedia.org/wiki/Z%C5%82oto\" target=\"_blank\" rel=\"noopener noreferrer\">złoto</a></i>. Zdrobnienie imienia Zlatan to Zlatko, używane jest również jako samodzielne imię. Żeńskie formy tego imienia to <a href=\"https://pl.wikipedia.org/wiki/Zlata\" target=\"_blank\" rel=\"noopener noreferrer\">Zlata</a> i Zlatica.", "Zdzislaw": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zdzisława</b>.</p><b>Zdzisława</b>, <i><b>Zdziesława</b></i> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Zdzis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Zdzisław</a>. Patronką tego imienia w Kościele katolickim jest bł. Zdzisława Czeska, patronka młodych małżeństw i matek.", "Zohar": "Jest napisany po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejsku</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajsku</a>. Dzieło spisał prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/Moj%C5%BCesz_ben_Szem_Tow\" target=\"_blank\" rel=\"noopener noreferrer\">Mojżesz z Leonu</a>, ale zawiera ono także fragmenty wcześniejszego pochodzenia. Środowiska ortodoksyjne przypisują autorstwo Zoharu <a href=\"https://pl.wikipedia.org/wiki/Szymon_bar_Jochaj\" target=\"_blank\" rel=\"noopener noreferrer\">Szymonowi bar Jochajowi</a>, <a href=\"https://pl.wikipedia.org/wiki/Tannaici\" target=\"_blank\" rel=\"noopener noreferrer\">tanaicie</a> z II wieku. Poza komentarzami do wspomnianych ksiąg zawiera rozważania, interpretacje <a href=\"https://pl.wikipedia.org/wiki/Halacha\" target=\"_blank\" rel=\"noopener noreferrer\"><i>halachy</i></a>, traktaty o <a href=\"https://pl.wikipedia.org/wiki/Chiromancja\" target=\"_blank\" rel=\"noopener noreferrer\">chiromancji</a> i fragmenty filozoficzno-mistyczne. Do dziś pozostaje podstawowym tekstem żydowskiej <a href=\"https://pl.wikipedia.org/wiki/Mistycyzm\" target=\"_blank\" rel=\"noopener noreferrer\">mistyki</a> i <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej</a> <a href=\"https://pl.wikipedia.org/wiki/Kaba%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">kabały</a>. Poruszane są w nim zagadnienia natury <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Boga</a>, powstania i kształtu świata, natury <a href=\"https://pl.wikipedia.org/wiki/Dusza_(religia)\" target=\"_blank\" rel=\"noopener noreferrer\">duszy</a>, <a href=\"https://pl.wikipedia.org/wiki/Grzech\" target=\"_blank\" rel=\"noopener noreferrer\">grzechu</a>, <a href=\"https://pl.wikipedia.org/wiki/Zbawienie\" target=\"_blank\" rel=\"noopener noreferrer\">odkupienia</a>, <a href=\"https://pl.wikipedia.org/wiki/Dobro\" target=\"_blank\" rel=\"noopener noreferrer\">dobra</a> i <a href=\"https://pl.wikipedia.org/wiki/Z%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">zła</a> oraz pokrewne.", "Żelisław": "Od tego imienia pochodzi nazwa miasta <a href=\"https://pl.wikipedia.org/wiki/%C5%BBelech%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Żelechów</a>.", "Zeeshan": "<p>Zeeshan, Zishan, Zeshaan lub Zeshan (perskie: ذیشان, ذی شان; arabski: ذِي شأن, romanized: ḏī-šaʔn, lit. 'posiadacz wspaniałości') to arabskie imię, po prostu przetłumaczone jako \"książę\".</p>", "Zacheusz": "<b>Zacheusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia hebrajskiego, od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i>כָּי (Zakkai)</i>, co oznacza „czysty”. Wśród patronów tego imienia – <a href=\"https://pl.wikipedia.org/wiki/Zacheusz_z_Jerozolimy\" target=\"_blank\" rel=\"noopener noreferrer\">św. Zacheusz</a>, biskup <a href=\"https://pl.wikipedia.org/wiki/Jerozolima\" target=\"_blank\" rel=\"noopener noreferrer\">Jerozolimy</a>. Znany jest także <a href=\"https://pl.wikipedia.org/wiki/Zacheusz_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Zacheusz</a> z <a href=\"https://pl.wikipedia.org/wiki/Ewangelia_%C5%81ukasza\" target=\"_blank\" rel=\"noopener noreferrer\">Ewangelii św. Łukasza</a>, który chcąc zobaczyć <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a> wspiął się w <a href=\"https://pl.wikipedia.org/wiki/Jerycho\" target=\"_blank\" rel=\"noopener noreferrer\">Jerychu</a> na <a href=\"https://pl.wikipedia.org/wiki/Figowiec_sykomora\" target=\"_blank\" rel=\"noopener noreferrer\">sykomorę</a>.", "Zayn": "<p>Zayn Jawadd Malik (ang. Zain Javadd Malik; rodzaj.</p>", "Zac": "<p>Zac to męskie imię, często skrócona forma Zachary. Może odnosić się do:</p>", "Zion": "<p>Zion (Sion) to dziesiąty album norweskiego producenta muzycznego Alexandra Winter'a pod pseudonimem Savant, wydany 13 grudnia 2014 roku przez nagrańę SectionZ Records.</p>", "Zane": "<p>Zein (Seyn, Zain, Zane, Zayn, Zeine) - nazwisko. Znani nosiciele: Zein, Alex (ur.</p>", "Zhivko": "<p>Zhivko (zirylicki: Живко) to bułgarskie męskie imię. Wariant serbo-chorwackiego tej samej nazwy jest Živko.</p>", "Zygmund": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zigmund</b>.</p><p>Zygmunt, Zigmunt, Zigmund i ich różnice pisowni są męskimi nazwiskami i czasami nazwiską. Ma tę samą etymologię jak germańska nazwa Sigismund.</p>", "Zdenek": "<p>Zdeněk to czeskie imię męskie pochodzące od łacińskiego imienia Sidonius. Jan Svoboda (języczni) kwestionował związek z łacińską nazwą, a alternatywna etimologia jest diminutiwem Zdesława.</p>", "Ziggy": "<p>Ziggy to męskie imię, często diminutiwna forma (hipokoryzm) Zigmunt i innych nazw. To też jest nazwa.</p>", "Zaman": "<p>Zaman (z tureckiego - ⁇ Wrem ⁇) - turecka gazeta.</p>", "Zyndram": "<b>Zyndram</b> – imię pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe ze słów <i>sind</i> i <i>Rabe</i> (co w tłumaczeniu na język polski oznacza kruka), raczej rzadko spotykane. Imię to nosił jeden z dowódców polskiego rycerstwa w bitwie pod Grunwaldem, <a href=\"https://pl.wikipedia.org/wiki/Zyndram_z_Maszkowic\" target=\"_blank\" rel=\"noopener noreferrer\">Zyndram z Maszkowic</a>.", "Zacharias": "<p>Otto Zacharias (niem. Emil Otto Zacharias; 27 stycznia 1846, Leipzig - 2 października 1916, Kiel) - niemiecki zoolog, badacz planktonu i dziennikarz.</p>", "Zeus": "<p>Słoneczniki (lat. Zeus) - rodzaj promieniowanych ryb z rodziny słoneczników (Zeidae) oddziału słonecznikow.</p>", "Zaheer": "<p>Zaheer jest postacią w amerykańskiej serii animowanych The Legend of Korra, następcą serii Avatar: The Last Airbender. Postać głosowana przez Henry Rollins i po raz pierwszy pojawiła się w trzecim sezonie serialu.</p>", "Zarif": "<p>Zarif Davidson, najbardziej znana pod swoim mononimem Zarif Davidson (ang.</p>", "Zalman": "<p>Zalman (złman, kor. 잘만) - południowo koreańska firma produkująca różne komponenty do komputerów z naciskiem na ulepszenie chłodzenia.</p>", "Zabar": "<p>Zabar jest miastem w hrabstwie Nógrád w Węgrzech. Miasto ma powierzchnię 18,17 km2, liczba ludności w 2010 roku wynosi 553 mieszkańców, a jego gęstość wynosi 30 mieszkańców/km2.</p>", "Zynovii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zinovii</b>.</p><p>Zinovy lub Zinovi (rosyjski: Зиновий, romanizowany: Zinoviy; ukraiński: Зиновій, romanized: Zynoviy) to wschodnio-słowiańskie imię męskie pochodzące od Zenobios. Zmiany kobiece: rosyjski: Zinovia, ukraiński: Zynoviia (por.</p>", "Zeyad": "<p>Ziad (arabski: زياد, romanized: Ziād) to arabskie imię i nazwisko.</p>", "Zelig": "<p>Zelig - film reżysera Woody'ego Allena.</p>", "Zidan": "<p>Zidan lub bardziej formalnie Zaydan jest nazwiskiem i nazwiskiem w różnych kulturach. Jako arabska nazwa (زيدان) jest również rzymsko zwana Zidane lub Zeidan.</p>", "Zoro": "<p>Zorro (jap. ゾロ) - japoński grupy rockowej.</p>", "Ziemisław": "<b>Siemisław</b>, <b>Siemosław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Siemo(i)-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*sěmьja</i> ma m.in. znaczenia „rodzina, ród; czeladź, służba, własność”) i <i>-sław</i> („sława”). Imię to wyraża życzenie sławy w przestrzeni rodzinnej.", "Zisis": "<p>Zisis (grecki: Ζήσης) jest zarówno greckim męskim nazwiskiem i nazwiskiem. Do wybitnych osób z tym nazwiskiem należą:</p>", "Zhou": "<p>Zhou Zhunghe (kiit.: 周忠和; ur. 19 stycznia 1965) - chiński paleontolog.</p>", "Zhao": "<p>Zhao Ermi (kiet. Wręcz przeciwnie.</p>", "Zabit": "<p>Zabit (arabsko: زابيت; rosyjsko: Забит) to męskie nazwisko pochodzenia arabskiego w Azji Środkowo-Azyjskiej. Może odnosić się do: Zabit Magomedsharipov (ur. 1991), rosyjski artysta walki mieszanej etnicznej Avar Zabit Samedov (ur. 1984), azerbajdżanki kickboxer</p>", "Zygbert": "<b>Zybert</b>, <b>Zybracht</b>, <b>Zybart</b>, <b>Zygbert</b>, Zygisbert – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> germańskie, notowane w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/1480\" target=\"_blank\" rel=\"noopener noreferrer\">1480</a> roku w formach <b>Zybart</b> i <b>Zybert</b>. Pierwszym członem imienia jest <i>sig</i>: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starosakso%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">stsas.</a> <i>sigi</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">stwniem.</a> <i>sigu</i> — \"zwycięstwo\" albo <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germ.</a> <i>sigis</i>. Forma ściągnięta <i>sī</i> &lt; <i>sii</i> powstała bardzo wcześnie na terenach <a href=\"https://pl.wikipedia.org/wiki/Frankonia\" target=\"_blank\" rel=\"noopener noreferrer\">zachodniofrankońskich</a> na skutek zaniku międzywokalicznego <i>-g-</i>. Drugi człon imienia, <i>-bert</i>, wywodzi się z pnia <i>bercht</i>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germ.</a> <i>berhta</i> — \"jasny\". Forma <i>-bert</i>, pozbawiona śródgłosowego <i>-h-</i>, jest charakterystyczna dla <a href=\"https://pl.wikipedia.org/wiki/Antroponimia\" target=\"_blank\" rel=\"noopener noreferrer\">nazw osobowych</a> przekazywanych przez <a href=\"https://pl.wikipedia.org/wiki/Pi%C5%9Bmiennictwo\" target=\"_blank\" rel=\"noopener noreferrer\">piśmiennictwo</a> <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a>, zaś forma <i>-bart</i> jest wynikiem obniżenia <i>e</i> &gt; <i>a</i>. Niektóre możliwe staropolskie zdrobnienia: Zyka, Zyc.", "Żytomir": "<b>Żytomir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owia%C5%84szczyzna\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>. Znaczenie imienia: „pragnący żyć w pokoju”", "Zander": "<p>Zander, Robert Zander &amp; Ingeström</p>", "Zenobi": "<b>Zenobiusz</b>, <b>Zenobi</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, złożone z członów <i>Dzeno-</i> (<a href=\"https://pl.wikipedia.org/wiki/Homer\" target=\"_blank\" rel=\"noopener noreferrer\">homerycka</a> forma imienia <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a>) i <i>bios</i> („życie”). Wymowa <i>Zenobios</i>, zamiast pierwotnej <i>Dzenobios</i>, pochodzi z czasów rzymskich.", "Zayne": "<p>Zayne i Zayn są alternatywnymi sposobami pisania nazwy Zane, a także rumowniami arabskiego unisexu nazwy Zain (زين), co oznacza \"Piękno\". Zayn i Zayne mogą odnosić się do:</p>", "Zidane": "<p>Zinedine Zid Zidane (francuski: Zinedine Yazid Zidane)  Zinédine Yazid Zidane, Kabeli.</p>", "Zvonimir": "<p>Zvonimir to chorwackie imię męskie, używane od średniowiecza. Nazwa ta była popularna w byłej Jugosławii wśród chorwatów, ponieważ Dmitar Zvonimir był królem Chorwatia, który rządził od 1075 do 1089 roku.</p>", "Żegota": "<b>Żegota</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>. Wywodzi się od słowa <i>żec</i> (czyli „palić”). Imię Żegota uważano za polskie tłumaczenie imienia <a href=\"https://pl.wikipedia.org/wiki/Ignacy\" target=\"_blank\" rel=\"noopener noreferrer\">Ignacy</a> (ze względu na podobieństwo znaczeniowe do łacińskiego <i>ignis</i> – „ogień”). Pojawiło się jednak w polskich zapisach w <a href=\"https://pl.wikipedia.org/wiki/1212\" target=\"_blank\" rel=\"noopener noreferrer\">1212</a> roku, a więc ponad sto lat wcześniej niż Ignacy.", "Zbylut": "<b>Zbylut</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> (również w odmianie Zbijlud i Zbilut), męskie, złożone z dwóch członów: <i>Zby-</i> („zbyć się, pozbyć się”) i <i>-lut</i> („srogi, ostry”). Mogło oznaczać „tego, który pozbył się srogości”.", "Zef": "<b>Zef</b> – <a href=\"https://pl.wikipedia.org/wiki/Kontrkultura\" target=\"_blank\" rel=\"noopener noreferrer\">kontrkultura</a> wywodząca się z <a href=\"https://pl.wikipedia.org/wiki/Po%C5%82udniowa_Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Republiki Południowej Afryki</a>. Słowo <i>zef</i> pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_afrikaans\" target=\"_blank\" rel=\"noopener noreferrer\">południowoafrykańskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Slang\" target=\"_blank\" rel=\"noopener noreferrer\">slangu</a> i oznacza w wolnym tłumaczeniu „wspólny”, „powszechny”, „ogólny”. Jack Parow, raper z <a href=\"https://pl.wikipedia.org/wiki/Kapsztad\" target=\"_blank\" rel=\"noopener noreferrer\">Kapsztadu</a>, w wywiadzie mówi o zef: „<i>coś jakby ekskluzywny, ale przeciwieństwo ekskluzywnego”.</i> Yo-landi Visser, raperka z grupy <a href=\"https://pl.wikipedia.org/wiki/Die_Antwoord\" target=\"_blank\" rel=\"noopener noreferrer\">Die Antwoord</a>, określa to tak: „Jesteś <i>zef</i> wtedy, kiedy jesteś biedny, ale <i>fancy</i>. Biedny, ale seksowny, kiedy masz styl”.", "Zwi": "<p>Zvi (Hebrajskie: צְבִי i צבי , Tzvi, Ṣvi, \"gazelle\") jest żydowskim męskim imieniem. Czasami jest połączone z Hirsch, niemieckim i jydskim słowem dla \"cerwa\", w dwujęzycznym pleonasmie.</p>", "Zeno": "Dowodził wojskami w <a href=\"https://pl.wikipedia.org/wiki/Antiochia\" target=\"_blank\" rel=\"noopener noreferrer\">Antiochii</a>. Przyczynił się do upadku wszechwładnego wodza, <a href=\"https://pl.wikipedia.org/wiki/Alanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Alana</a> <a href=\"https://pl.wikipedia.org/wiki/Flawiusz_Ardaburiusz_Aspar\" target=\"_blank\" rel=\"noopener noreferrer\">Aspara</a> w <a href=\"https://pl.wikipedia.org/wiki/471\" target=\"_blank\" rel=\"noopener noreferrer\">471</a>. Za panowania swego syna <a href=\"https://pl.wikipedia.org/wiki/Leon_II_(cesarz)\" target=\"_blank\" rel=\"noopener noreferrer\">Leona II Małego</a> występował w jego imieniu jako <a href=\"https://pl.wikipedia.org/wiki/Regent\" target=\"_blank\" rel=\"noopener noreferrer\">regent</a>. W <a href=\"https://pl.wikipedia.org/wiki/475\" target=\"_blank\" rel=\"noopener noreferrer\">475</a> utracił władzę w wyniku rewolty <a href=\"https://pl.wikipedia.org/wiki/Bazyliskus\" target=\"_blank\" rel=\"noopener noreferrer\">Bazyliskusa</a>, który ogłosił się cesarzem. W sierpniu <a href=\"https://pl.wikipedia.org/wiki/476\" target=\"_blank\" rel=\"noopener noreferrer\">476</a> wkroczył do <a href=\"https://pl.wikipedia.org/wiki/Konstantynopol\" target=\"_blank\" rel=\"noopener noreferrer\">Konstantynopola</a>, usunął Bazyliskusa i odzyskał władzę. W <a href=\"https://pl.wikipedia.org/wiki/477\" target=\"_blank\" rel=\"noopener noreferrer\">477</a> roku kazał zamordować <a href=\"https://pl.wikipedia.org/wiki/Armatus\" target=\"_blank\" rel=\"noopener noreferrer\">Armatusa</a>. Pełnił urząd <a href=\"https://pl.wikipedia.org/wiki/Konsul_rzymski\" target=\"_blank\" rel=\"noopener noreferrer\">konsula</a> w 479 . W tym samym roku <a href=\"https://pl.wikipedia.org/wiki/Odoaker\" target=\"_blank\" rel=\"noopener noreferrer\">Odoaker</a> odesłał mu insygnia cesarskie <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_zachodniorzymskie\" target=\"_blank\" rel=\"noopener noreferrer\">z zachodu</a> i uznał jego formalne zwierzchnictwo. Mimo tego, Zeno poparł później przeciwko Odoakrowi władcę <a href=\"https://pl.wikipedia.org/wiki/Ostrogoci\" target=\"_blank\" rel=\"noopener noreferrer\">Ostrogotów</a> <a href=\"https://pl.wikipedia.org/wiki/Teodoryk_Wielki\" target=\"_blank\" rel=\"noopener noreferrer\">Teodoryka</a>, który <a href=\"https://pl.wikipedia.org/wiki/Podb%C3%B3j_Italii_przez_Got%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">w 489 najechał Italię</a>, w 493 usunął rywala i założył w niej <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Ostrogot%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">własne królestwo</a>.", "Zoubir": "<p>Zoubir to arabskie męskie imię i nazwisko.</p>", "Zigmund": "<p>Zygmunt, Zigmunt, Zigmund i ich różnice pisowni są męskimi nazwiskami i czasami nazwiską. Ma tę samą etymologię jak germańska nazwa Sigismund.</p>", "Zainal": "<p>Zainal to imię i nazwisko. Znani ludzie z tej nazwy to: Zainal Abidin z Ternate, 18. sultan Ternate od 1486 do 1500 Zainal Arifin Paliwang (ur. 1962), indonezyjski polityk Ahmad Azlan Zainal (ur. 1986), malezyjski piłkarz Mizan Zainal Abdin, 16. sultan stanu Terengganu i 13. król Malezji Sultan Mizan Zainali Abidin Stadium, nowy stadion wielofunkcyjny w Kuala Terengganu, Malezja Mohd Amirul ...</p>", "Zacharie": "<p>Zacharie to zarówno męskie francuskie imię, jak i nazwisko. Do znanych osób z tym samym nazwiskiem należą:</p>", "Żak": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zac</b>.</p><p>Zac to męskie imię, często skrócona forma Zachary. Może odnosić się do:</p>", "Zorik": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zorika</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zorica</b>.</p><p>Zorica (krylickie: Зорица) to kobiece imię. Znanymi osobami z nazwiska są: Zorica Dimitrijević-Stošić (1934-2013), serbska pianista, akompaniysta, pełnoprawny profesor fortepianu na Wydziale Muzyki w Belgradzie Zorica Ðurković (urodzona 1957), były piłkarz koszykówki Zorica Jevremović (urodzona 1948), dyrektor teatralny i wideo, dramaturg, choreograf Zorica Pantić (ur. około roku 1957).</p>", "Żywisław": "<b>Żywisław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/Neologizm\" target=\"_blank\" rel=\"noopener noreferrer\">neologizm</a> utworzony na wzór imion <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owia%C5%84szczyzna\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskich</a>. Nienotowane w źródłach <a href=\"https://pl.wikipedia.org/wiki/Staropolszczyzna\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskich</a>. Człon <i>Żywi-</i> jest niespotykany w staropolskich imionach dwuczłonowych.", "Zeljko": "<p>Željko (czyrylicki: Жељко), czasami napisany Zeljko, jest sławskim nazwa męska. W Chorwacji nazwa Željko była jedną z najczęstszych imion męskich w latach 1950-1979 i była najczęstszą w latach 60.</p>", "Zaharia": "<p>Zaharia jest albaniańską i rumuńską wariantką nazwiska lub nazwiska Zachariah/Zacharias.</p>", "Zygfrid": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zygfryd</b>.</p><b>Zygfryd</b>, <b>Sygurd</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>sigu</i> i <i>fridu</i> oznaczających <i>zwycięstwo</i> i <i>opieka</i>, jako ten, który zapewnia bezpieczeństwo swym podopiecznym. Imię to było znane w Polsce od średniowiecza, m.in. w formach: Zebrzyd, Zybrzyd, Zewrzyd, Zywrzyd. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Zygfryda\" target=\"_blank\" rel=\"noopener noreferrer\">Zygfryda</a>.", "Zeshan": "<p>Zeeshan, Zishan, Zeshaan lub Zeshan (perskie: ذیشان, ذی شان; arabski: ذِي شأن, romanized: ḏī-šaʔn, lit. 'posiadacz wspaniałości') to arabskie imię, po prostu przetłumaczone jako \"książę\".</p>", "Zoe": "<b>Zoe</b>, <b>Zoja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznaczające „życie” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ζωή). W postaci <i>Zoja</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">ros.</a>&#160;Зоя) imię to występuje przede wszystkim w krajach <a href=\"https://pl.wikipedia.org/wiki/Europa_Wschodnia\" target=\"_blank\" rel=\"noopener noreferrer\">wschodnioeuropejskich</a>.", "Zdzisław Kazimierz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zdzisław</b>.</p><b>Zdzisław</b>, <i><b>Zdziesław</b></i> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z dwóch członów: <i>Zdzie (Zdzi-)</i> (\"uczynić, zdziałać, zrobić\") i <i>-sław</i> (\"sława\"). Zanotowane w dokumentach z roku 1198.", "Zbigniew Kazimierz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zbigniew</b>.</p><b>Zbigniew</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Złożone jest z dwóch członów: <i>Zby-</i> („zbyć, zbyć się, pozbyć się”) i <i>-gniew</i> („gniew”). Mogło oznaczać „tego, który się zbył (pozbył) gniewu”. Właściwie powinno ono brzmieć <b>Zbygniew</b>, a Zbigniew to wynik zniekształcenia, które nastąpiło przy odczycie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a> przez pierwszych badaczy. W Polsce imię to po raz pierwszy odnotowano jako <i>Zbygniew</i>. Do końca <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a> imię Zbygniew zanotowano u około 1000 osób.", "Zhijian": "<p>Zhijian jest pisownią Pinyin wielu różnych chińskich nazw. Nazy te są również pisowane Chih-chien w romanizmowaniu Wade-Giles powszechne na Tajwanie, a Chi-kin w typowym języku kantonowskim w Hongkongu .</p>", "Zenzo": "<p>Zenzō, Zenzo lub Zenzou jest męskim japońskim imieniem.</p>", "Zen": "<b>Zen</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;禅&#59; cicha medytacja, religijna kontemplacja, z <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">skt.</a> ध्यान <i>Dhyāna</i>, poprzez <a href=\"https://pl.wikipedia.org/wiki/Tradycyjne_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chin. trad.</a> 禪那, <a href=\"https://pl.wikipedia.org/wiki/Uproszczone_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chin. upr.</a> 禅那, 禅, <a href=\"https://pl.wikipedia.org/wiki/Hanyu_pinyin\" target=\"_blank\" rel=\"noopener noreferrer\">pinyin</a>: <i>chánnà</i>, <i><a href=\"https://pl.wikipedia.org/wiki/Chan_(buddyzm)\" target=\"_blank\" rel=\"noopener noreferrer\">chán</a></i>) – nurt <a href=\"https://pl.wikipedia.org/wiki/Buddyzm\" target=\"_blank\" rel=\"noopener noreferrer\">buddyzmu</a>, który w pełni rozwiniętą formę uzyskał w <a href=\"https://pl.wikipedia.org/wiki/Chiny_(region)\" target=\"_blank\" rel=\"noopener noreferrer\">Chinach</a> (zob. <a href=\"https://pl.wikipedia.org/wiki/Chan_(buddyzm)\" target=\"_blank\" rel=\"noopener noreferrer\">chan</a>), skąd przedostał się do <a href=\"https://pl.wikipedia.org/wiki/Korea\" target=\"_blank\" rel=\"noopener noreferrer\">Korei</a>, <a href=\"https://pl.wikipedia.org/wiki/Wietnam\" target=\"_blank\" rel=\"noopener noreferrer\">Wietnamu</a> i <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">Japonii</a>. Wywodzi się z rodziny buddyzmu <a href=\"https://pl.wikipedia.org/wiki/Mahajana\" target=\"_blank\" rel=\"noopener noreferrer\">mahajany</a>, ale na przestrzeni wieków nabrał wyrazistego indywidualnego stylu, pełnego minimalizmu i zamierzonych <a href=\"https://pl.wikipedia.org/wiki/Paradoks\" target=\"_blank\" rel=\"noopener noreferrer\">paradoksów</a>.", "Zyad": "<p>Ziad (arabski: زياد, romanized: Ziād) to arabskie imię i nazwisko.</p>", "Zhu": "<p>Stephen Zoo (ang. Steven Zhu; rodzaj.</p>", "Zulfikar": "<i>Zulfikar</i> (też w innych wariantach fonetycznych i ortograficznych) jest również często nadawanym w krajach arabskojęzycznych imieniem, nosił je na przykład <a href=\"https://pl.wikipedia.org/wiki/Zulfikar_Ali_Bhutto\" target=\"_blank\" rel=\"noopener noreferrer\">Zulfikar Ali Bhutto</a>, w latach 1971–1973 prezydent, a w 1973–1977 – premier <a href=\"https://pl.wikipedia.org/wiki/Pakistan\" target=\"_blank\" rel=\"noopener noreferrer\">Pakistanu</a>.", "Zbigniev": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zbigniew</b>.</p><b>Zbigniew</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Złożone jest z dwóch członów: <i>Zby-</i> („zbyć, zbyć się, pozbyć się”) i <i>-gniew</i> („gniew”). Mogło oznaczać „tego, który się zbył (pozbył) gniewu”. Właściwie powinno ono brzmieć <b>Zbygniew</b>, a Zbigniew to wynik zniekształcenia, które nastąpiło przy odczycie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a> przez pierwszych badaczy. W Polsce imię to po raz pierwszy odnotowano jako <i>Zbygniew</i>. Do końca <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a> imię Zbygniew zanotowano u około 1000 osób.", "Zadar": "<b>Zadar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Za-</i> (być może tu: \"jako\") i <i>-dar</i> (\"upominek, dar, ofiara\"). Mogło oznaczać \"tego, kto pojawił się jako dar\", \"tego, kto jest darem\".", "Zelik": "<p>Zelig (jiddish: זעליג, hebrajsky: זליג) jest męskim nazwiskiem i nazwiskiem, co oznacza \"błogosławiony\" w języku jiddskim. Warianty nazwy obejmują Zelik (jiddish: זעליק) i Selig (jiddisch: סעליג).</p>", "Zine": "<b>Zin</b>, <b>fanzin</b> (skrót od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>fan magazine</em>) – rodzaj nieprofesjonalnego pisma tworzonego przez osobę bądź grupę osób – miłośników jakiegoś tematu (np. <a href=\"https://pl.wikipedia.org/wiki/Muzyka\" target=\"_blank\" rel=\"noopener noreferrer\">muzyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Informatyka\" target=\"_blank\" rel=\"noopener noreferrer\">informatyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Literatura\" target=\"_blank\" rel=\"noopener noreferrer\">literatury</a>, <a href=\"https://pl.wikipedia.org/wiki/Fantastyka\" target=\"_blank\" rel=\"noopener noreferrer\">fantastyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Gra_fabularna\" target=\"_blank\" rel=\"noopener noreferrer\">gier fabularnych</a>, <a href=\"https://pl.wikipedia.org/wiki/Ekologia\" target=\"_blank\" rel=\"noopener noreferrer\">ekologii</a>, <a href=\"https://pl.wikipedia.org/wiki/Polityka\" target=\"_blank\" rel=\"noopener noreferrer\">polityki</a>), skierowane do osób podzielających owe zainteresowania.", "Zhuang": "<b>Zhuang</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">chiń.</a> 壮族 <a href=\"https://pl.wikipedia.org/wiki/Hanyu_pinyin\" target=\"_blank\" rel=\"noopener noreferrer\">pinyin</a>: Zhuàngzú) inaczej <b>Zhuangowie</b>, <b>Czuangowie</b> – <a href=\"https://pl.wikipedia.org/wiki/Nar%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">naród</a> <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">azjatycki</a> pochodzenia środkowotajskiego, osiadły w południowych <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chinach</a> i północnym <a href=\"https://pl.wikipedia.org/wiki/Wietnam\" target=\"_blank\" rel=\"noopener noreferrer\">Wietnamie</a> (<a href=\"https://pl.wikipedia.org/wiki/N%C3%B9ng\" target=\"_blank\" rel=\"noopener noreferrer\">Nùngowie</a>). Najliczniejsza <a href=\"https://pl.wikipedia.org/wiki/Mniejszo%C5%9Bci_narodowe_w_Chi%C5%84skiej_Republice_Ludowej\" target=\"_blank\" rel=\"noopener noreferrer\">mniejszość etniczna Chińskiej Republiki Ludowej</a> (ok. 18 mln os.). Przeważnie zamieszkują <a href=\"https://pl.wikipedia.org/wiki/Kuangsi\" target=\"_blank\" rel=\"noopener noreferrer\">Region Autonomiczny Kuangsi–Czuang</a> oraz prowincje <a href=\"https://pl.wikipedia.org/wiki/Junnan\" target=\"_blank\" rel=\"noopener noreferrer\">Junnan</a>, <a href=\"https://pl.wikipedia.org/wiki/Guangdong\" target=\"_blank\" rel=\"noopener noreferrer\">Guangdong</a>, <a href=\"https://pl.wikipedia.org/wiki/Kuejczou\" target=\"_blank\" rel=\"noopener noreferrer\">Kuejczou</a> i <a href=\"https://pl.wikipedia.org/wiki/Hunan\" target=\"_blank\" rel=\"noopener noreferrer\">Hunan</a>. Wyróżnia się dwa zespoły pomniejszych grup etnicznych: północnych i południowych Zhuangów. Posługują się <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_zhuang\" target=\"_blank\" rel=\"noopener noreferrer\">językiem zhuang</a>, zróżnicowanym gwarowo.", "Zofia": "<b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Z": "<b>Z</b> (<i>zet</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>z</b>) – dwudziesta szósta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, trzydziesta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. Litera ta pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Alfabet_fenicki\" target=\"_blank\" rel=\"noopener noreferrer\">fenickiej</a> (północno-zachodnio-semickiej) litery zaîn, poprzez <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecką literę</a> ζ (<a href=\"https://pl.wikipedia.org/wiki/Dzeta\" target=\"_blank\" rel=\"noopener noreferrer\">dzeta</a>, zeta). W języku polskim oznacza spółgłoskę przedniojęzykowo-zębową, szczelinową, dźwięczną [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">z̪</a>], w języku niemieckim [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarto-szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ʦ</a>], a w hiszpańskim [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_mi%C4%99dzyz%C4%99bowa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">θ</a>].", "Zi": "<b>Zi</b> – <a href=\"https://pl.wikipedia.org/wiki/Dwuznak\" target=\"_blank\" rel=\"noopener noreferrer\">dwuznak</a> występujący w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">języku polskim</a>, oznacza <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">literę</a> <a href=\"https://pl.wikipedia.org/wiki/%C5%B9\" target=\"_blank\" rel=\"noopener noreferrer\">ź</a> z samogłoską <a href=\"https://pl.wikipedia.org/wiki/A\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>, <a href=\"https://pl.wikipedia.org/wiki/%C4%84\" target=\"_blank\" rel=\"noopener noreferrer\">ą</a>, <a href=\"https://pl.wikipedia.org/wiki/E\" target=\"_blank\" rel=\"noopener noreferrer\">e</a>, <a href=\"https://pl.wikipedia.org/wiki/%C4%98\" target=\"_blank\" rel=\"noopener noreferrer\">ę</a>, <a href=\"https://pl.wikipedia.org/wiki/I\" target=\"_blank\" rel=\"noopener noreferrer\">i</a>, <a href=\"https://pl.wikipedia.org/wiki/O\" target=\"_blank\" rel=\"noopener noreferrer\">o</a>, <a href=\"https://pl.wikipedia.org/wiki/U\" target=\"_blank\" rel=\"noopener noreferrer\">u</a>, w niektórych przypadkach <i>zi</i> wymawia się jak <i>zji</i>, w przykładzie słów nazw własnych na przykład przy słowie <a href=\"https://pl.wikipedia.org/wiki/Zimbabwe\" target=\"_blank\" rel=\"noopener noreferrer\">Zimbabwe</a> (kraju położonego w <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryce</a>), gdzie dźwiękiem pierwszej litery słowa nie brzmi <i>ź</i>, lecz <a href=\"https://pl.wikipedia.org/wiki/Palatalizacja\" target=\"_blank\" rel=\"noopener noreferrer\">zmiękczone</a> <a href=\"https://pl.wikipedia.org/wiki/Z\" target=\"_blank\" rel=\"noopener noreferrer\">z</a>. W pozostałych językach <i>zi</i> to nie dwuznak tylko 2 oddzielne litery.", "Zyon": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zion</b>.</p><p>Zion (Sion) to dziesiąty album norweskiego producenta muzycznego Alexandra Winter'a pod pseudonimem Savant, wydany 13 grudnia 2014 roku przez nagrańę SectionZ Records.</p>", "Zhonghe": "Populacja dzielnicy Zhonghe w 2016 roku liczyła 414&#160;266 mieszkańców – 212&#160;434 kobiet i 201&#160;832 mężczyzn. Liczba gospodarstw domowych wynosiła 164&#160;248, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 2,52 osób.", "Zwonimir": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zvonimir</b>.</p><p>Zvonimir to chorwackie imię męskie, używane od średniowiecza. Nazwa ta była popularna w byłej Jugosławii wśród chorwatów, ponieważ Dmitar Zvonimir był królem Chorwatia, który rządził od 1075 do 1089 roku.</p>", "Zine-Eddine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zine</b>.</p><b>Zin</b>, <b>fanzin</b> (skrót od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>fan magazine</em>) – rodzaj nieprofesjonalnego pisma tworzonego przez osobę bądź grupę osób – miłośników jakiegoś tematu (np. <a href=\"https://pl.wikipedia.org/wiki/Muzyka\" target=\"_blank\" rel=\"noopener noreferrer\">muzyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Informatyka\" target=\"_blank\" rel=\"noopener noreferrer\">informatyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Literatura\" target=\"_blank\" rel=\"noopener noreferrer\">literatury</a>, <a href=\"https://pl.wikipedia.org/wiki/Fantastyka\" target=\"_blank\" rel=\"noopener noreferrer\">fantastyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Gra_fabularna\" target=\"_blank\" rel=\"noopener noreferrer\">gier fabularnych</a>, <a href=\"https://pl.wikipedia.org/wiki/Ekologia\" target=\"_blank\" rel=\"noopener noreferrer\">ekologii</a>, <a href=\"https://pl.wikipedia.org/wiki/Polityka\" target=\"_blank\" rel=\"noopener noreferrer\">polityki</a>), skierowane do osób podzielających owe zainteresowania.", "Zoia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zoya</b>.</p><p>Zoja (rosyjski: Зоя) to kobiece nazwisko rosyjskie, ukraińskie, białoruskie i bułgarskie, forma Zoe, oznaczająca \"życie\", z greckiego ζωή (zoē), \"życie\".</p>", "Zbigniew Stanisław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zbigniew</b>.</p><b>Zbigniew</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Złożone jest z dwóch członów: <i>Zby-</i> („zbyć, zbyć się, pozbyć się”) i <i>-gniew</i> („gniew”). Mogło oznaczać „tego, który się zbył (pozbył) gniewu”. Właściwie powinno ono brzmieć <b>Zbygniew</b>, a Zbigniew to wynik zniekształcenia, które nastąpiło przy odczycie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a> przez pierwszych badaczy. W Polsce imię to po raz pierwszy odnotowano jako <i>Zbygniew</i>. Do końca <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a> imię Zbygniew zanotowano u około 1000 osób.", "Zdrawko": "<b>Zdrawko</b> (Zdravko) – imię południowosłowiańskie utworzone od słowa „zdrowy”.", "Zvezdan": "<p>Zvezdan (Serbski: Звездан) jest słowiańskim męskim imieniem. Do wybitnych osób z tym nazwiskiem należą: Zvezdan Čebinac (ur. 1939), były serbski były półoczniak i menedżer piłki nożnej Zvezdan Jovanović (ur. 1965), zabójca byłego premiera Serbii Zorana Đinđića w 2003 roku Zvezdan Martič, słoweński dziennikarz i inżynier Zvezdan Pejović (urat. 1966), emerytowany jugosławski obrońca piłki noży zawodowej Zvezdan Terzić...</p>", "Zofian": "<b>Zofian</b> – imię męskie pochodzące od żeńskiego imienia o greckim rodowodzie <b><a href=\"https://pl.wikipedia.org/wiki/Zofia_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Zofia</a></b>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Zhili": "<i>Zhili</i> oznacza \"[obszar] bezpośrednio rządzony\"; mianem tym za wczesnej dynastii Ming określano dwa obszary, które ze względu na swoje znaczenie gospodarcze i obronne zarządzane były bezpośrednio przez dwór cesarski:", "Zois": "<p>Zois to nazwisko i męskie nazwisko, które mogą odnosić się do: Antonios Zois (1869-1941), greckiego szefa Chris Zois, amerykańskiego psychiatra i autora Christos Zois (ur. 1968), greckego polityka Karla von Zois (1756-1799), karnaolskiego amatera botanika i kolekcjoner roślin Peter Zoïs (ur. 1978), australijskiego menedżera piłki nożnej i emerytura gracza Sigmund Zois (1747-1819), karnaolskiego szlachtańca, naturalisty i patron sztuk Zois Ballas (ur. ...</p>", "Zahi̇d": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zahida</b>.</p><p>Zahida to kobiece imię arabskiego pochodzenia. Do wybitnych osób z tym nazwiskiem należą:</p>", "Zeiad": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zeyad</b>.</p><p>Ziad (arabski: زياد, romanized: Ziād) to arabskie imię i nazwisko.</p>", "Zbigniew Andrzej": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zbigniew</b>.</p><b>Zbigniew</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Złożone jest z dwóch członów: <i>Zby-</i> („zbyć, zbyć się, pozbyć się”) i <i>-gniew</i> („gniew”). Mogło oznaczać „tego, który się zbył (pozbył) gniewu”. Właściwie powinno ono brzmieć <b>Zbygniew</b>, a Zbigniew to wynik zniekształcenia, które nastąpiło przy odczycie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a> przez pierwszych badaczy. W Polsce imię to po raz pierwszy odnotowano jako <i>Zbygniew</i>. Do końca <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a> imię Zbygniew zanotowano u około 1000 osób.", "Zackery": "<p>Zachariasz (hebrajski: זְכַרְיָה), z wieloma różnymi formami i pisowniami, takimi jak Zachariasz i Zachariasz, jest teoforycznym męskim imieniem pochodzenia hebrajskiego, co oznacza \"Bóg/JHWH pamięta\". Pochodzi od hebrajskiego korzenia זכר (lat. zakhar), co oznacza pamiętać, a ja, jedno z imion Boga Izraela.</p>", "Zayden": "<p>Zayden () jest wariantem męskiego nazwiska Aidan (nazwa). Popularność Zayden jako imienia dla dzieci w Stanach Zjednoczonych osiągnęła szczyt w 2014 roku, kiedy osiągnęło 188. miejsce.</p>", "Zine Eddine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zine</b>.</p><b>Zin</b>, <b>fanzin</b> (skrót od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>fan magazine</em>) – rodzaj nieprofesjonalnego pisma tworzonego przez osobę bądź grupę osób – miłośników jakiegoś tematu (np. <a href=\"https://pl.wikipedia.org/wiki/Muzyka\" target=\"_blank\" rel=\"noopener noreferrer\">muzyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Informatyka\" target=\"_blank\" rel=\"noopener noreferrer\">informatyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Literatura\" target=\"_blank\" rel=\"noopener noreferrer\">literatury</a>, <a href=\"https://pl.wikipedia.org/wiki/Fantastyka\" target=\"_blank\" rel=\"noopener noreferrer\">fantastyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Gra_fabularna\" target=\"_blank\" rel=\"noopener noreferrer\">gier fabularnych</a>, <a href=\"https://pl.wikipedia.org/wiki/Ekologia\" target=\"_blank\" rel=\"noopener noreferrer\">ekologii</a>, <a href=\"https://pl.wikipedia.org/wiki/Polityka\" target=\"_blank\" rel=\"noopener noreferrer\">polityki</a>), skierowane do osób podzielających owe zainteresowania.", "Zaffar": "<p>Zafar, Zaffar, Zufar to imię i nazwisko pochodzenia arabskiego. Wśród znanych osób z nazwiskiem są: Nazwa: Bahadur Shah II (1775-1862), ostatni cesarz Mughal, znany również pod nazwą pluma, Zafar Khoja Zufar (1500-1546), arabski kupiec Zafar Ahmad Usmani (1892-1974), sunnijski jurysta Zafar Ali Khan (1873-1956), pakistański pisarz Zafar Ali Naqvi (ur. 1948), indyjski polityk Zafar Ansari (ur. 1991), emerytowany angielski kryker z...</p>", "Zigbert": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zygbert</b>.</p><b>Zybert</b>, <b>Zybracht</b>, <b>Zybart</b>, <b>Zygbert</b>, Zygisbert – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> germańskie, notowane w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/1480\" target=\"_blank\" rel=\"noopener noreferrer\">1480</a> roku w formach <b>Zybart</b> i <b>Zybert</b>. Pierwszym członem imienia jest <i>sig</i>: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starosakso%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">stsas.</a> <i>sigi</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">stwniem.</a> <i>sigu</i> — \"zwycięstwo\" albo <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germ.</a> <i>sigis</i>. Forma ściągnięta <i>sī</i> &lt; <i>sii</i> powstała bardzo wcześnie na terenach <a href=\"https://pl.wikipedia.org/wiki/Frankonia\" target=\"_blank\" rel=\"noopener noreferrer\">zachodniofrankońskich</a> na skutek zaniku międzywokalicznego <i>-g-</i>. Drugi człon imienia, <i>-bert</i>, wywodzi się z pnia <i>bercht</i>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germ.</a> <i>berhta</i> — \"jasny\". Forma <i>-bert</i>, pozbawiona śródgłosowego <i>-h-</i>, jest charakterystyczna dla <a href=\"https://pl.wikipedia.org/wiki/Antroponimia\" target=\"_blank\" rel=\"noopener noreferrer\">nazw osobowych</a> przekazywanych przez <a href=\"https://pl.wikipedia.org/wiki/Pi%C5%9Bmiennictwo\" target=\"_blank\" rel=\"noopener noreferrer\">piśmiennictwo</a> <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a>, zaś forma <i>-bart</i> jest wynikiem obniżenia <i>e</i> &gt; <i>a</i>. Niektóre możliwe staropolskie zdrobnienia: Zyka, Zyc.", "Zrinko": "<p>Zrinko jest słowiańskim nazwiskiem pochodzenia chorwackiego i pochodzi od nazwy miejsca Zrin, które znajduje się w regionie Banovina, Chorwacja. Nazwa ta może odnosić się do: Zrinko Ogresta, chorwatyjski reżyser filmowy Zrinko Tutić, chorwatski autor utworów</p>", "Zlatibor": "Zlatibor jest położony w północnej części regionu Stari Vlah, historycznej granicy między regionami <a href=\"https://pl.wikipedia.org/wiki/Ra%C5%A1ka\" target=\"_blank\" rel=\"noopener noreferrer\">Rašką</a>, <a href=\"https://pl.wikipedia.org/wiki/Hercegowina\" target=\"_blank\" rel=\"noopener noreferrer\">Hercegowiną</a> i <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%9Bnia_(region)\" target=\"_blank\" rel=\"noopener noreferrer\">Bośnią</a>. Szczyt <a href=\"https://pl.wikipedia.org/wiki/Cigla\" target=\"_blank\" rel=\"noopener noreferrer\">Cigla</a> w pobliżu wsi jest szczytem granicznym pomiędzy <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Serbii\" target=\"_blank\" rel=\"noopener noreferrer\">Królestwem Serbii</a>, <a href=\"https://pl.wikipedia.org/wiki/Austro-W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">Austro-Węgrami</a> i <a href=\"https://pl.wikipedia.org/wiki/Imperium_Osma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Imperium Osmańskim</a>. W starożytności Zlatibor był nazywany <b>Rujno</b>, a <a href=\"https://pl.wikipedia.org/wiki/%C5%BBupa_(jednostka_administracyjna)\" target=\"_blank\" rel=\"noopener noreferrer\">żupa</a> była częścią Raški. Nazwa Zlatibor pojawiła się w <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII wieku</a>, ale jej etymologia jest wątpliwa. Najbardziej prawdopodobną wersją jest połączenie dwóch serbskich słów <i>zlatni</i> (złoty) i <i>bor</i> (sosna).", "Zek": "<b>Zek</b> – wywodzące się z socjolektu łagrowego ogólne określenie na więźnia systemu <a href=\"https://pl.wikipedia.org/wiki/Gu%C5%82ag\" target=\"_blank\" rel=\"noopener noreferrer\">Gułagu</a> w <a href=\"https://pl.wikipedia.org/wiki/Zwi%C4%85zek_Socjalistycznych_Republik_Radzieckich\" target=\"_blank\" rel=\"noopener noreferrer\">ZSRR</a>. Nazwa pochodzi od skrótu <i>z/k</i> stosowanego w państwowych dokumentach oznaczającego osobę uwięzioną.", "Zubin": "<p>Zubin (persk: زوبین) to perskie imię męskie, które dosłownie oznacza \"coś, co dotyka nieba\" i powszechnie odnosi się do krótkiego rodzaju włóczni w perskim. W mitologii perskiej Zubin (zwany również: Zupin, Zhubin, Zhupin) był legendarnym perskim wojownikiem słynnym ze swojej odwagi i dowodzenia wojskowego, co nadaje znaczenie \"człowieka, który dotknął nieba\". Zubin oznaczał również \"borużkę\", ogólnie odnosząc się do \"krótkiej włóczni [który jest rzucony...</p>", "Zbrosław": "<b>Zbrosław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>Zbro-</i> (<i>borti</i> - „walczyć”, „zmagać się”) i <i>-sław</i> („sława”). Oznacza ono „tego, czyja sława tworzy się dzięki walce”. Jedną z form skróconych tego imienia był <a href=\"https://pl.wikipedia.org/wiki/Bros%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Brosław</a>.", "Ziemowit Kazimierz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ziemowit</b>.</p><b>Ziemowit</b> – zniekształcona forma <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Siemowit_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Siemowit</a> oznaczającego „głowę rodu”.", "Zi Tong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zi</b>.</p><b>Zi</b> – <a href=\"https://pl.wikipedia.org/wiki/Dwuznak\" target=\"_blank\" rel=\"noopener noreferrer\">dwuznak</a> występujący w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">języku polskim</a>, oznacza <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">literę</a> <a href=\"https://pl.wikipedia.org/wiki/%C5%B9\" target=\"_blank\" rel=\"noopener noreferrer\">ź</a> z samogłoską <a href=\"https://pl.wikipedia.org/wiki/A\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>, <a href=\"https://pl.wikipedia.org/wiki/%C4%84\" target=\"_blank\" rel=\"noopener noreferrer\">ą</a>, <a href=\"https://pl.wikipedia.org/wiki/E\" target=\"_blank\" rel=\"noopener noreferrer\">e</a>, <a href=\"https://pl.wikipedia.org/wiki/%C4%98\" target=\"_blank\" rel=\"noopener noreferrer\">ę</a>, <a href=\"https://pl.wikipedia.org/wiki/I\" target=\"_blank\" rel=\"noopener noreferrer\">i</a>, <a href=\"https://pl.wikipedia.org/wiki/O\" target=\"_blank\" rel=\"noopener noreferrer\">o</a>, <a href=\"https://pl.wikipedia.org/wiki/U\" target=\"_blank\" rel=\"noopener noreferrer\">u</a>, w niektórych przypadkach <i>zi</i> wymawia się jak <i>zji</i>, w przykładzie słów nazw własnych na przykład przy słowie <a href=\"https://pl.wikipedia.org/wiki/Zimbabwe\" target=\"_blank\" rel=\"noopener noreferrer\">Zimbabwe</a> (kraju położonego w <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryce</a>), gdzie dźwiękiem pierwszej litery słowa nie brzmi <i>ź</i>, lecz <a href=\"https://pl.wikipedia.org/wiki/Palatalizacja\" target=\"_blank\" rel=\"noopener noreferrer\">zmiękczone</a> <a href=\"https://pl.wikipedia.org/wiki/Z\" target=\"_blank\" rel=\"noopener noreferrer\">z</a>. W pozostałych językach <i>zi</i> to nie dwuznak tylko 2 oddzielne litery.", "Zuzanna": "<b>Zuzanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שׁוֹשַׁנָּה&#8206; (<i>szoszana</i>), zapożyczonego przez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">język grecki</a>, a pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שׁוֹשָׁן&#8206; (<i>szoszan</i>), oznaczającego „lilia”, co z kolei prawdopodobnie wywodziło się od egipskiego <i>seszen</i>, czyli „lotos”. W Polsce imię to jest notowane w dokumentach od 1265 roku, w formach Zuzanna/Żużanna, a także pochodnych: Zanna/Żanna, Zanka/Zańka, Ożanka (zob. też <a href=\"https://pl.wikipedia.org/wiki/O%C5%BCanna_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Ożanna</a>), Zużka, Zuchna, Oszka. Wśród imion nadawanych nowo narodzonym dzieciom, Zuzanna w 2017 zajmowała 2. miejsce w grupie imion żeńskich.", "Zorró": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zoro</b>.</p><p>Zorro (jap. ゾロ) - japoński grupy rockowej.</p>", "Zbigniew Józef": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zbigniew</b>.</p><b>Zbigniew</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Złożone jest z dwóch członów: <i>Zby-</i> („zbyć, zbyć się, pozbyć się”) i <i>-gniew</i> („gniew”). Mogło oznaczać „tego, który się zbył (pozbył) gniewu”. Właściwie powinno ono brzmieć <b>Zbygniew</b>, a Zbigniew to wynik zniekształcenia, które nastąpiło przy odczycie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a> przez pierwszych badaczy. W Polsce imię to po raz pierwszy odnotowano jako <i>Zbygniew</i>. Do końca <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a> imię Zbygniew zanotowano u około 1000 osób.", "Zorzan": "<b>Zoran</b> (<a href=\"https://pl.wikipedia.org/wiki/Cyrylica_serbska\" target=\"_blank\" rel=\"noopener noreferrer\">cyrylica serbska</a>: Зоран) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">południowosłowiańskie</a>, wywodzące się od słowa <i>zora</i> czyli „zorza, świt, jutrznia”.", "Zbysław Kazimierz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zbysław</b>.</p><b>Zbysław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z dwóch członów: <i>Zby-</i> („zbyć się, pozbyć się”) i <i>-sław</i>.", "Zdzisław Jerzy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zdzisław</b>.</p><b>Zdzisław</b>, <i><b>Zdziesław</b></i> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z dwóch członów: <i>Zdzie (Zdzi-)</i> (\"uczynić, zdziałać, zrobić\") i <i>-sław</i> (\"sława\"). Zanotowane w dokumentach z roku 1198.", "Zoro-Furişor": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zoro</b>.</p><p>Zorro (jap. ゾロ) - japoński grupy rockowej.</p>", "Zbigniew Marian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zbigniew</b>.</p><b>Zbigniew</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Złożone jest z dwóch członów: <i>Zby-</i> („zbyć, zbyć się, pozbyć się”) i <i>-gniew</i> („gniew”). Mogło oznaczać „tego, który się zbył (pozbył) gniewu”. Właściwie powinno ono brzmieć <b>Zbygniew</b>, a Zbigniew to wynik zniekształcenia, które nastąpiło przy odczycie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a> przez pierwszych badaczy. W Polsce imię to po raz pierwszy odnotowano jako <i>Zbygniew</i>. Do końca <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a> imię Zbygniew zanotowano u około 1000 osób.", "Zhann": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zhanna</b>.</p><p>Zhanna to rosyjska forma imienia Jeanne. Znanymi osobami z tej nazwy są: Zhanna Agalakova (ur. 1965), rosyjska dziennikarz Zhanna Aguzarova (ur., 1962), sowiecka i rosyjska piosenkarka Zhanna Bichevskaya (ur. 1944), wybitna rosyjska barda i muzyka ludowa Zhanna Friske (1974-2015), rosyjskie aktorka filmowa, piosenkarz i socjaltynka Zhanna Pintusevich-Block (ur. 1972), biegacz, który uczestniczył w igrzyskach olimpijskich Zhanna Prokhorenko ...</p>", "Zephyr": "Protokół umożliwia przesyłanie komunikatów podzielonych na rodzaje (<a href=\"https://pl.wikipedia.org/wiki/Klasa_(programowanie_obiektowe)\" target=\"_blank\" rel=\"noopener noreferrer\">klasy</a> i ich <a href=\"https://pl.wikipedia.org/wiki/Instancja_(programowanie)\" target=\"_blank\" rel=\"noopener noreferrer\">instancje</a>). Istnieje możliwość odbierania wyłącznie wybranych klas komunikatów. Protokół umożliwia również sprawdzanie, czy inny użytkownik jest obecny w systemie, z jakiej stacji sieciowej korzysta, oraz otrzymywanie informacji o logowaniu się i wylogowywaniu się użytkowników z systemu. Użytkownicy mogą określić na ile ich obecność w systemie ma być widoczna dla innych użytkowników. Komunikaty systemu są nazywane „zefirami” <i>(zephyrs)</i>, „zefirogramami” <i>(zephyrgrams)</i>, „oknogramami” <i>(zephyr windowgrams)</i> i są w przenoszą proste wiadomości tekstowe lub informacje o zdarzeniach.", "Zygmunt Antoni": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zygmunt</b>.</p><b>Zygmunt</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie oraz <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Składa się ze słów: <i>sigu</i> oznaczającego „zwycięstwo” i <i>mund</i> lub <i>munt</i>, „opieka”, „tarcza”. Można je zatem tłumaczyć jako „obrona przez zwycięstwo”.", "Zinowii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zinovii</b>.</p><p>Zinovy lub Zinovi (rosyjski: Зиновий, romanizowany: Zinoviy; ukraiński: Зиновій, romanized: Zynoviy) to wschodnio-słowiańskie imię męskie pochodzące od Zenobios. Zmiany kobiece: rosyjski: Zinovia, ukraiński: Zynoviia (por.</p>", "Ziemovit": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ziemowit</b>.</p><b>Ziemowit</b> – zniekształcona forma <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Siemowit_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Siemowit</a> oznaczającego „głowę rodu”.", "Zinaida": "<b>Zenaida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (Ζηναΐς), oznaczające pierwotnie osobę poświęconą <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusowi</a>. Odnotowano dwie święte katolickie o tym imieniu, w tym <a href=\"https://pl.wikipedia.org/wiki/Zenaida_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">Zenaida z Tarsu</a> (męczennica, również święta <a href=\"https://pl.wikipedia.org/wiki/Prawos%C5%82awie\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławna</a>).", "Zbygniew": "<b>Zbigniew</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Złożone jest z dwóch członów: <i>Zby-</i> („zbyć, zbyć się, pozbyć się”) i <i>-gniew</i> („gniew”). Mogło oznaczać „tego, który się zbył (pozbył) gniewu”. Właściwie powinno ono brzmieć <b>Zbygniew</b>, a Zbigniew to wynik zniekształcenia, które nastąpiło przy odczycie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a> przez pierwszych badaczy. W Polsce imię to po raz pierwszy odnotowano jako <i>Zbygniew</i>. Do końca <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a> imię Zbygniew zanotowano u około 1000 osób.", "Zbynek": "<p>Zbyněk (czeski wymowa: [zbɪɲɛk]) jest czeskim męskim imieniem. W polskim jest to Zbigniew.</p>", "Zara": "<p>Zara (szp. Zara [θara]) - wiodąca sieć handlowa grupy firm Inditex, należąca do hiszpańskiego magnata Amancia Ortega, który jest również właścicielem takich mark jak Massimo Dutti, Pull &amp; Bear, Oysho, Zara Home, Uterqüe, Stradivarius, Lefties i Bershka.</p>", "Zebedeusz": "Imię Zebedeusz oznacza <i><a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Bóg</a> dał</i>.", "Złatan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zlatana</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zlatan</b>.</p><b>Zlatan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a>&#160;Златан) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>. Popularne jest zwłaszcza wśród narodów <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie_po%C5%82udniowi\" target=\"_blank\" rel=\"noopener noreferrer\">południowosłowiańskich</a>; <a href=\"https://pl.wikipedia.org/wiki/Chorwaci\" target=\"_blank\" rel=\"noopener noreferrer\">Chorwatów</a>, <a href=\"https://pl.wikipedia.org/wiki/Serbowie\" target=\"_blank\" rel=\"noopener noreferrer\">Serbów</a>, <a href=\"https://pl.wikipedia.org/wiki/Boszniacy\" target=\"_blank\" rel=\"noopener noreferrer\">Boszniaków</a>, <a href=\"https://pl.wikipedia.org/wiki/Macedo%C5%84czycy\" target=\"_blank\" rel=\"noopener noreferrer\">Macedończyków</a>, <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garzy\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgarów</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owe%C5%84cy\" target=\"_blank\" rel=\"noopener noreferrer\">Sloweńców</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_po%C5%82udniowos%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">południowosłowiańskiego</a> słowa <i>zlato</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a>&#160;злато) oznaczającego w języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a> <i><a href=\"https://pl.wikipedia.org/wiki/Z%C5%82oto\" target=\"_blank\" rel=\"noopener noreferrer\">złoto</a></i>. Zdrobnienie imienia Zlatan to Zlatko, używane jest również jako samodzielne imię. Żeńskie formy tego imienia to <a href=\"https://pl.wikipedia.org/wiki/Zlata\" target=\"_blank\" rel=\"noopener noreferrer\">Zlata</a> i Zlatica.", "Zivai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ziva</b>.</p><p>Ziwa, Ziva lub Zhiva, to pierwotnie hebrajskie imię. Ziva to imię dla kobiet i równie rzadkie nazwisko.</p>", "Zhanna": "<p>Zhanna to rosyjska forma imienia Jeanne. Znanymi osobami z tej nazwy są: Zhanna Agalakova (ur. 1965), rosyjska dziennikarz Zhanna Aguzarova (ur., 1962), sowiecka i rosyjska piosenkarka Zhanna Bichevskaya (ur. 1944), wybitna rosyjska barda i muzyka ludowa Zhanna Friske (1974-2015), rosyjskie aktorka filmowa, piosenkarz i socjaltynka Zhanna Pintusevich-Block (ur. 1972), biegacz, który uczestniczył w igrzyskach olimpijskich Zhanna Prokhorenko ...</p>", "Zalmai": "<p>Zalmay, Zalmai, Zalmeh lub Zalmie to męskie imię pasztunskie, które występuje wśród pasztunów Pakistanu i Afganistanu. Jego znaczenie jest po prostu przetłumaczone jako \"młody człowiek\" lub \"młodziak\".</p>", "Zdzisława": "<b>Zdzisława</b>, <i><b>Zdziesława</b></i> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Zdzis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Zdzisław</a>. Patronką tego imienia w Kościele katolickim jest bł. Zdzisława Czeska, patronka młodych małżeństw i matek.", "Żaneta": "<b>Żaneta</b><b>, Żanetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a>, spolszczona forma imienia <i>Jeanette</i> (zdrobnienia od <i>Jeanne</i>, pol. <a href=\"https://pl.wikipedia.org/wiki/Janina\" target=\"_blank\" rel=\"noopener noreferrer\">Janina</a> lub <a href=\"https://pl.wikipedia.org/wiki/Joanna\" target=\"_blank\" rel=\"noopener noreferrer\">Joanna</a>).", "Zenona": "<b>Zenona</b> – imię żeńskie greckiego pochodzenia, odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Zenon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Zenon</a>.", "Zenobia": "<b>Zenobia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Zenobiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Zenobiusz</a>, złożonego z członów <i>Dzeno-</i> (<a href=\"https://pl.wikipedia.org/wiki/Homer\" target=\"_blank\" rel=\"noopener noreferrer\">homerycka</a> forma imienia <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a>) i <i>bios</i> („życie”). Zenobia jest zatem <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99_teoforyczne\" target=\"_blank\" rel=\"noopener noreferrer\">imieniem teoforycznym</a>. Patronką tego imienia jest św. Zenobia, siostra św. <a href=\"https://pl.wikipedia.org/wiki/Zenobiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Zenobiusza</a>, żyjąca w czasach cesarza <a href=\"https://pl.wikipedia.org/wiki/Dioklecjan\" target=\"_blank\" rel=\"noopener noreferrer\">Dioklecjana</a>.", "Zyta": "<b>Zyta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od pospolitego <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a>&#160;<em>zitta</em>, z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>zita</em>, oznaczającego „dziewczynę”. Chrześcijańską patronką tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Zyta_z_Lukki\" target=\"_blank\" rel=\"noopener noreferrer\">Zyta z Lukki</a>, która jako jedyna wprowadziła to imię do kalendarzy. <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">Imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/27_kwietnia\" target=\"_blank\" rel=\"noopener noreferrer\">27 kwietnia</a>.", "Żaklina": "<b>Żaklina</b> – spolszczenie francuskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i>Jacqueline</i>, zapisane fonetycznie, które jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Jakub_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakub</a>. Jest również inny żeński odpowiednik tego imienia – <a href=\"https://pl.wikipedia.org/wiki/Jakubina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakubina</a>. Niektórzy błędnie uważają to imię za żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Jacek\" target=\"_blank\" rel=\"noopener noreferrer\">Jacek</a> (mylnie interpretując francuskie imię <i>Jacques</i>).", "Żanetta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Żaneta</b>.</p><b>Żaneta</b><b>, Żanetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a>, spolszczona forma imienia <i>Jeanette</i> (zdrobnienia od <i>Jeanne</i>, pol. <a href=\"https://pl.wikipedia.org/wiki/Janina\" target=\"_blank\" rel=\"noopener noreferrer\">Janina</a> lub <a href=\"https://pl.wikipedia.org/wiki/Joanna\" target=\"_blank\" rel=\"noopener noreferrer\">Joanna</a>).", "Zoya": "<p>Zoja (rosyjski: Зоя) to kobiece nazwisko rosyjskie, ukraińskie, białoruskie i bułgarskie, forma Zoe, oznaczająca \"życie\", z greckiego ζωή (zoē), \"życie\".</p>", "Zarina": "<p>Zarina jest nazwą żeńską pochodzącą od słowiańskiego słowa \"czar / tzar\" (царь), tytułu używanego przez sławskich monarchów lub najwyższych władców, a czasami także sufiksu (itsa), tytułu kobiety władcy autokratycznej (monarch) Bułgarii lub Rosji, lub tytułu żony czara. W starożytnej kulturze Sri Lanki bogini Zarina była powszechnie związana z bogiem podziemia, Harikesh.</p>", "Żanna": "<b>Żanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, powstałe najprawdopodobniej pod wpływem rosyjskim, przez fonetyczne zapisanie francuskiej wersji imienia <b><a href=\"https://pl.wikipedia.org/wiki/Joanna\" target=\"_blank\" rel=\"noopener noreferrer\">Joanna</a></b>, czyli <i>Jeanne</i>.", "Zenaida": "<b>Zenaida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (Ζηναΐς), oznaczające pierwotnie osobę poświęconą <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusowi</a>. Odnotowano dwie święte katolickie o tym imieniu, w tym <a href=\"https://pl.wikipedia.org/wiki/Zenaida_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">Zenaida z Tarsu</a> (męczennica, również święta <a href=\"https://pl.wikipedia.org/wiki/Prawos%C5%82awie\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławna</a>).", "Zbigniewa": "<b>Zbygniewa</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Zbigniew\" target=\"_blank\" rel=\"noopener noreferrer\">Zbygniew</a>. Złożone jest z dwóch członów: <i>Zby-</i> (\"zbyć, zbyć się, pozbyć się\") i <i>-gniewa</i> (\"gniew\"). Oznacza prawdopodobnie \"tę, która się zbyła (pozbyła) gniewu\". Istnieje też tłumaczenie alternatywne: „miej zbytek (nadmiar) gniewu” (gniew – jako zapał wojenny – był uważany za cnotę).", "Żaklin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Żaklina</b>.</p><b>Żaklina</b> – spolszczenie francuskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i>Jacqueline</i>, zapisane fonetycznie, które jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Jakub_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakub</a>. Jest również inny żeński odpowiednik tego imienia – <a href=\"https://pl.wikipedia.org/wiki/Jakubina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakubina</a>. Niektórzy błędnie uważają to imię za żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Jacek\" target=\"_blank\" rel=\"noopener noreferrer\">Jacek</a> (mylnie interpretując francuskie imię <i>Jacques</i>).", "Zinoviia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zinovii</b>.</p><p>Zinovy lub Zinovi (rosyjski: Зиновий, romanizowany: Zinoviy; ukraiński: Зиновій, romanized: Zynoviy) to wschodnio-słowiańskie imię męskie pochodzące od Zenobios. Zmiany kobiece: rosyjski: Zinovia, ukraiński: Zynoviia (por.</p>", "Zefiryna": "<b>Zefiryna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Zefiryn\" target=\"_blank\" rel=\"noopener noreferrer\">Zefiryn</a>. Jest to imię <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99_teoforyczne\" target=\"_blank\" rel=\"noopener noreferrer\">teoforyczne</a>, utworzone za pomocą sufiksu <i>-inus</i> od imienia greckiego boga wiatru zachodniego (<i>Zéphyros</i>).", "Zygfryda": "<b>Zygfryda</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskie</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Zygfryd\" target=\"_blank\" rel=\"noopener noreferrer\">Zygfryd</a>. Wywodzi się od słów <i>sigu</i> i <i>fridu</i> oznaczających <i>zwycięstwo</i> i <i>pokój</i>, a zatem imię to może oznaczać „zaprowadzająca pokój dzięki zwycięstwu”. Patronami tego imienia są św. Zygfrydowie.", "Zita": "<p>Zita (1212 r., Monsagrati, w pobliżu miasta Lucca, Obszar Toskana, Włochy - 27 kwietnia 1272 r., Lucca, Włoch) - święta rzymskokatolicka, czci się jako patronka pokojówek i służących w domu.</p>", "Żywia": "<b>Żywia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia słowiańskiego. Imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Siwa_(bogini_s%C5%82owia%C5%84ska)\" target=\"_blank\" rel=\"noopener noreferrer\">Żywii</a>, słowiańskiej bogini życia, płodności i wiosny.", "Zainab": "<p>Zaynab, i jego warianty, to arabskie imię dla kobiet, które oznacza \" kwiat w pustyni \". Zainab bint Muhammad była córką islamskiego proroka Muhammada, Zaynab bint Ali była wnuczką, dwie z jego żon były Zaynab binti Jahsh i Zaynab bin Khuzayma.</p>", "Zarema": "<p>Zarema Halilova (ur. 1983, SZS, SZR), znana jako Zarema - amerykańska piosenkarka i aktorka pochodzenia krymskiego.</p>", "Zoey": "<p>Zoe to żeńskie imię pochodzenia greckiego, oznaczające \"życie\".</p>", "Zygryda": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zigrida</b>.</p><p>Sigrid to skandynawskie imię dla kobiet z starożytnego norweskiego Sigríðr, składające się z elementów sigr \"wygrę\" i fríðr \"piękna\". Powszechne krótkie formy obejmują Siri, Sigga, Sig i Sigi.</p>", "Zygmunta": "<b>Zygmunta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Zygmunt\" target=\"_blank\" rel=\"noopener noreferrer\">Zygmunt</a>. Wywodzi się od słów: <i>sigu</i> oznaczającego „zwycięstwo” i <i>munt</i> - „opieka”, czyli ta, której opieka zapewnia zwycięstwo.", "Zelma": "<p>Salcedia (lat. Salcedia) - rodzaj żuraczów-żuraczów z podrodzin skaryta (Scaritinae, plemię Salcediini). Około 20 gatunków.</p>", "Zeinab": "<p>Zaynab, i jego warianty, to arabskie imię dla kobiet, które oznacza \" kwiat w pustyni \". Zainab bint Muhammad była córką islamskiego proroka Muhammada, Zaynab bint Ali była wnuczką, dwie z jego żon były Zaynab binti Jahsh i Zaynab bin Khuzayma.</p>", "Zbysława": "<b>Zbysława</b> – żeński odpowiednik staropolskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Zbys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Zbysław</a>. Składa się z dwóch członów: <i>Zby-</i> („zbyć się, pozbyć się”) i <i>-sława</i>.", "Zyglinda": "<b>Zyglinda</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskie</a>, złożone z członów <i>sig</i> – \"zwycięstwo\" i <i>lind</i> – \"miękka, łagodna\" lub \"tarcza ochronna\". Patronką tego imienia jest św. Zyglinda (<a href=\"https://pl.wikipedia.org/wiki/Segolena\" target=\"_blank\" rel=\"noopener noreferrer\">Segolena</a>), <a href=\"https://pl.wikipedia.org/wiki/Opat\" target=\"_blank\" rel=\"noopener noreferrer\">ksieni</a> z Troclar (w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Albi\" target=\"_blank\" rel=\"noopener noreferrer\">Albi</a>).", "Zsófia": "<p>Sofia Węgierska (węgiersko Zsófia) ― członek dynastii Arpadów, córka króla Węgier Białego I i Rykes Polskiej.</p>", "Zenia": "<p>Zenia jest rodzajem roślin kwiatowych z rodziny Białorusi.</p>", "Zonia": "<p>Zonia jest motylem dnia z rodziny Mroźnych Motylów.</p>", "Zelda": "<p>The Legend of Zelda (jap. ゼルダの伝説 Dzeruda no Densetsu) - seria gier w genie action-adventure, stworzona przez japońskich graczy-dyszynierów Sigerura Miyamoto i Takasi Tadzukę.</p>", "Żanet": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Żaneta</b>.</p><b>Żaneta</b><b>, Żanetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a>, spolszczona forma imienia <i>Jeanette</i> (zdrobnienia od <i>Jeanne</i>, pol. <a href=\"https://pl.wikipedia.org/wiki/Janina\" target=\"_blank\" rel=\"noopener noreferrer\">Janina</a> lub <a href=\"https://pl.wikipedia.org/wiki/Joanna\" target=\"_blank\" rel=\"noopener noreferrer\">Joanna</a>).", "Zofiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Zemfira": "<p>Zemfira Tolgatowna Ramazanova (ur. 26 sierpnia 1976, Ufa, B.A.S.R., S.S.S.), znana bardziej jako Zemfira, - rosyjska piosenkarka, autor- wykonawca, muzyka, kompozytor i producent muzyczny.</p>", "Zaryna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zarina</b>.</p><p>Zarina jest nazwą żeńską pochodzącą od słowiańskiego słowa \"czar / tzar\" (царь), tytułu używanego przez sławskich monarchów lub najwyższych władców, a czasami także sufiksu (itsa), tytułu kobiety władcy autokratycznej (monarch) Bułgarii lub Rosji, lub tytułu żony czara. W starożytnej kulturze Sri Lanki bogini Zarina była powszechnie związana z bogiem podziemia, Harikesh.</p>", "Zinoviya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zinoviy</b>.</p><p>Zinovy lub Zinovi (rosyjski: Зиновий, romanizowany: Zinoviy; ukraiński: Зиновій, romanized: Zynoviy) to wschodnio-słowiańskie imię męskie pochodzące od Zenobios. Zmiany kobiece: rosyjski: Zinovia, ukraiński: Zynoviia (por.</p>", "Żelisława": "<b>Żelisława</b> – staropolskie imię żeńskie; żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/%C5%BBelis%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Żelisław</a>. Znaczenie imienia: \"pragnąca sławy\".", "Zula": "<b>Zuzanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שׁוֹשַׁנָּה&#8206; (<i>szoszana</i>), zapożyczonego przez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">język grecki</a>, a pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שׁוֹשָׁן&#8206; (<i>szoszan</i>), oznaczającego „lilia”, co z kolei prawdopodobnie wywodziło się od egipskiego <i>seszen</i>, czyli „lotos”. W Polsce imię to jest notowane w dokumentach od 1265 roku, w formach Zuzanna/Żużanna, a także pochodnych: Zanna/Żanna, Zanka/Zańka, Ożanka (zob. też <a href=\"https://pl.wikipedia.org/wiki/O%C5%BCanna_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Ożanna</a>), Zużka, Zuchna, Oszka. Wśród imion nadawanych nowo narodzonym dzieciom, Zuzanna w 2017 zajmowała 2. miejsce w grupie imion żeńskich.", "Ziva": "<p>Ziwa, Ziva lub Zhiva, to pierwotnie hebrajskie imię. Ziva to imię dla kobiet i równie rzadkie nazwisko.</p>", "Zena": "<p>Zynaida Aleksandra Kuprijanovich (b. Zinaida Aleksandrawna Kuprianowicz, rodzina.</p>", "Zulfiya": "Urodziła się w rodzinie <a href=\"https://pl.wikipedia.org/wiki/%C5%BBydzi\" target=\"_blank\" rel=\"noopener noreferrer\">żydowskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Giser\" target=\"_blank\" rel=\"noopener noreferrer\">gisera</a>-chałupnika. Skończyła szkołę średnią i żeńską szkołę pedagogiczną, pracowała w redakcjach republikańskich gazet i pism, zaczęła pisać wiersze. W 1932, w wieku 17 lat, wydała swój pierwszy zbiór wierszy <i>Stranicy żyzni</i>, o młodzieży, przyjaźni i pięknie ludzkiej duszy. Od 1938 pracowała w różnych wydawnictwach, podczas <a href=\"https://pl.wikipedia.org/wiki/Front_wschodni_(II_wojna_%C5%9Bwiatowa)\" target=\"_blank\" rel=\"noopener noreferrer\">wojny ZSRR z Niemcami</a> pisała wiersze patriotyczne. W 1965 opublikowała zbiór wierszy <i>Kuylarim sizga</i> (<i>Śpiewam dla was</i>), a w 1971 poemat <i>Quyoshli qalam</i> (<i>Słoneczne pióro</i>). Pisała także artykuły prasowe o roli kobiety w rodzinie i społeczeństwie. Jej mężem był Hamid Olimjon, przewodniczący Związku Pisarzy Uzbekistanu. W Taszkencie jej imieniem nazwano ulicę, a w 2008 zbudowano jej pomnik. W 2004 ustanowiono Nagrodę Państwową im. Zulfiyi w dziedzinie literatury, sztuki, nauki, kultury i edukacji.", "Zora": "<p>Zora jest pająkiem z rodziny Zoridae.</p>", "Zaneta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Żanet</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Żaneta</b>.</p><b>Żaneta</b><b>, Żanetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a>, spolszczona forma imienia <i>Jeanette</i> (zdrobnienia od <i>Jeanne</i>, pol. <a href=\"https://pl.wikipedia.org/wiki/Janina\" target=\"_blank\" rel=\"noopener noreferrer\">Janina</a> lub <a href=\"https://pl.wikipedia.org/wiki/Joanna\" target=\"_blank\" rel=\"noopener noreferrer\">Joanna</a>).", "Zeina": "<p>Zeina jest egipską aktorką i modelką. Zaczęła występować w 1995 roku i od tego czasu występowała w wielu filmach i filmach telewizyjnych, w tym Afaryt el-Sayala (Ghosts of Sayala) (2004) i El Haya fe Montaha el Laza (Joys of Life) (2005).</p>", "Zeynab": "<p>Zaynab, i jego warianty, to arabskie imię dla kobiet, które oznacza \" kwiat w pustyni \". Zainab bint Muhammad była córką islamskiego proroka Muhammada, Zaynab bint Ali była wnuczką, dwie z jego żon były Zaynab binti Jahsh i Zaynab bin Khuzayma.</p>", "Zehava": "<p>Zehava lub Zahava (Hebrajsky: זֶהָבָה) to hebrajskie imię żeńskie, które może odnosić się do Zehava Ben (ur. 1968), izraelski wokalist Zahava Burack (1932-2001), amerykańskiego filantropu Zahava Elenberg, australijskiego architekta Zehava Gal, izraelsko-ur. operowego mezzo-soprano Zehava Gal-On (ur. 1956), izraelskich polityków Zehava Shmueli (ur. 1955), izraelskiego biegacza długodystansowego Goldilocks, w hebrajskiej wersji bajki Goldilocks i Trzech niedźwiedzi</p>", "Zygrida": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zygryda</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zigrida</b>.</p><p>Sigrid to skandynawskie imię dla kobiet z starożytnego norweskiego Sigríðr, składające się z elementów sigr \"wygrę\" i fríðr \"piękna\". Powszechne krótkie formy obejmują Siri, Sigga, Sig i Sigi.</p>", "Zaruhi": "<p>Zaruhi (armeńska: Զարուհի) to armenijska kobieca nazwa, która może odnosić się do Zarouhie Abdalian (ur. 1982), amerykańskiej artystki Zaruhi Babayan (ur. 1975, artystka z Armenii Zaruhi Bahri (1880-1958), armeńskiego pisarza Zaruhi Batoyan (ur. 1979), urzędnika rządu z Armenii, aktywisty Zari Elmassian (1906-1990) amerykańskiego piosenkarza Zaruhi Kalemkaryan (1871-1971), pisarza prozy, esejisty, poet i filantrop z Armenii pochodzenia Zaruhi Kavaljian ...</p>", "Zigrida": "<p>Sigrid to skandynawskie imię dla kobiet z starożytnego norweskiego Sigríðr, składające się z elementów sigr \"wygrę\" i fríðr \"piękna\". Powszechne krótkie formy obejmują Siri, Sigga, Sig i Sigi.</p>", "Zorika": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zorica</b>.</p><p>Zorica (krylickie: Зорица) to kobiece imię. Znanymi osobami z nazwiska są: Zorica Dimitrijević-Stošić (1934-2013), serbska pianista, akompaniysta, pełnoprawny profesor fortepianu na Wydziale Muzyki w Belgradzie Zorica Ðurković (urodzona 1957), były piłkarz koszykówki Zorica Jevremović (urodzona 1948), dyrektor teatralny i wideo, dramaturg, choreograf Zorica Pantić (ur. około roku 1957).</p>", "Zenajda": "<b>Zenaida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (Ζηναΐς), oznaczające pierwotnie osobę poświęconą <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusowi</a>. Odnotowano dwie święte katolickie o tym imieniu, w tym <a href=\"https://pl.wikipedia.org/wiki/Zenaida_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">Zenaida z Tarsu</a> (męczennica, również święta <a href=\"https://pl.wikipedia.org/wiki/Prawos%C5%82awie\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławna</a>).", "Zhazira": "<p>Zhazira lub Jazira (kazachski: Жазира) to kazachskie kobiece imię. Oznacza to \"wiosenny krajobraz stepy\".</p>", "Zofia Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Zofiya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Zarifa": "<p>Zarifa to imię i nazwisko pochodzące z arabskiego języka. Do wybitnych osób z tym nazwiskiem należą:</p>", "Zulay": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zulai</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zula</b>.</p><b>Zuzanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שׁוֹשַׁנָּה&#8206; (<i>szoszana</i>), zapożyczonego przez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">język grecki</a>, a pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שׁוֹשָׁן&#8206; (<i>szoszan</i>), oznaczającego „lilia”, co z kolei prawdopodobnie wywodziło się od egipskiego <i>seszen</i>, czyli „lotos”. W Polsce imię to jest notowane w dokumentach od 1265 roku, w formach Zuzanna/Żużanna, a także pochodnych: Zanna/Żanna, Zanka/Zańka, Ożanka (zob. też <a href=\"https://pl.wikipedia.org/wiki/O%C5%BCanna_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Ożanna</a>), Zużka, Zuchna, Oszka. Wśród imion nadawanych nowo narodzonym dzieciom, Zuzanna w 2017 zajmowała 2. miejsce w grupie imion żeńskich.", "Zorka": "<p>Zorka to staroświeckie słowiańskie imię, które oznacza świt.</p>", "Zinajda": "<b>Zenaida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (Ζηναΐς), oznaczające pierwotnie osobę poświęconą <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusowi</a>. Odnotowano dwie święte katolickie o tym imieniu, w tym <a href=\"https://pl.wikipedia.org/wiki/Zenaida_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">Zenaida z Tarsu</a> (męczennica, również święta <a href=\"https://pl.wikipedia.org/wiki/Prawos%C5%82awie\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławna</a>).", "Zeyneb": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zeineb</b>.</p><p>Zeineb lub Zejneb to bosniackie imię kobiety, transliteratowane z arabskiej nazwy Zaynab, i może odnosić się do: Zeineb Benzina, tunyjskiego archeologa</p>", "Zahraa": "<p>Zahraa (arabski: الزهراء) jest syryjską wioską znajdującą się w obszarze Jubb Ramishima w obszarzie Masyaf, Hama. Według Centralnego Biura Statystycznego Syrii (CBS), Zahraa miało populację 1019 w 2004 roku.</p>", "Żywila": "<b>Żywila</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia literackiego. Tytułowa postać wczesnego utworu <a href=\"https://pl.wikipedia.org/wiki/Adam_Mickiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Adama Mickiewicza</a>, jak również opartej na nim opery <a href=\"https://pl.wikipedia.org/wiki/Alojzy_Dworzaczek\" target=\"_blank\" rel=\"noopener noreferrer\">Alojzego Dworzaczka</a> z <a href=\"https://pl.wikipedia.org/wiki/Libretto\" target=\"_blank\" rel=\"noopener noreferrer\">librettem</a> Bronisławy Wilkoszewskiej (premiera <a href=\"https://pl.wikipedia.org/wiki/12_maja\" target=\"_blank\" rel=\"noopener noreferrer\">12 maja</a> <a href=\"https://pl.wikipedia.org/wiki/1926\" target=\"_blank\" rel=\"noopener noreferrer\">1926</a>). Prawdopodobnie powstało jako kontaminacja wymienionych w <i>Kronice</i> <a href=\"https://pl.wikipedia.org/wiki/Maciej_Stryjkowski\" target=\"_blank\" rel=\"noopener noreferrer\">Stryjkowskiego</a> imion dwóch pogańskich bóstw: <a href=\"https://pl.wikipedia.org/wiki/%C5%BBywie\" target=\"_blank\" rel=\"noopener noreferrer\">Żywie</a>, bóstwa — wiatru, oraz <i>Zizilii</i>, bogini stanowiącej odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Wenus_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Wenery</a>.", "Zeineb": "<p>Zeineb lub Zejneb to bosniackie imię kobiety, transliteratowane z arabskiej nazwy Zaynab, i może odnosić się do: Zeineb Benzina, tunyjskiego archeologa</p>", "Zanele": "<p>Zanele to kobiece imię, pochodzące od słowa Nguni anele, co oznacza \"wystarczające\". Znanymi osobami z nazwiska są: Zanele kaMagwaza-Msibi (1962-2021), południowoafrykański polityk Zanele Dlamini Mbeki (ur. 1938), połudnoafrykańska pracownik społeczny i była pierwsza dama Zanele Muholi (ur. 1972), artysta z południowej Afryki Zanele Nhlapho (ur. 1991), piłkarz południo Afryki, Zanele Nkomo, południowaafrykańskiego polityka Zanele Sifuba, południeafryka...</p>", "Zera": "<p>Zera jest motylem dnia z rodziny Mrowych Motylów.</p>", "Zdzisława Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zdzisława</b>.</p><b>Zdzisława</b>, <i><b>Zdziesława</b></i> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Zdzis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Zdzisław</a>. Patronką tego imienia w Kościele katolickim jest bł. Zdzisława Czeska, patronka młodych małżeństw i matek.", "Zulfiyya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zulfiya</b>.</p>Urodziła się w rodzinie <a href=\"https://pl.wikipedia.org/wiki/%C5%BBydzi\" target=\"_blank\" rel=\"noopener noreferrer\">żydowskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Giser\" target=\"_blank\" rel=\"noopener noreferrer\">gisera</a>-chałupnika. Skończyła szkołę średnią i żeńską szkołę pedagogiczną, pracowała w redakcjach republikańskich gazet i pism, zaczęła pisać wiersze. W 1932, w wieku 17 lat, wydała swój pierwszy zbiór wierszy <i>Stranicy żyzni</i>, o młodzieży, przyjaźni i pięknie ludzkiej duszy. Od 1938 pracowała w różnych wydawnictwach, podczas <a href=\"https://pl.wikipedia.org/wiki/Front_wschodni_(II_wojna_%C5%9Bwiatowa)\" target=\"_blank\" rel=\"noopener noreferrer\">wojny ZSRR z Niemcami</a> pisała wiersze patriotyczne. W 1965 opublikowała zbiór wierszy <i>Kuylarim sizga</i> (<i>Śpiewam dla was</i>), a w 1971 poemat <i>Quyoshli qalam</i> (<i>Słoneczne pióro</i>). Pisała także artykuły prasowe o roli kobiety w rodzinie i społeczeństwie. Jej mężem był Hamid Olimjon, przewodniczący Związku Pisarzy Uzbekistanu. W Taszkencie jej imieniem nazwano ulicę, a w 2008 zbudowano jej pomnik. W 2004 ustanowiono Nagrodę Państwową im. Zulfiyi w dziedzinie literatury, sztuki, nauki, kultury i edukacji.", "Zakia": "<p>Zakiya, Zakia, Zakiyah, Zakiyya lub Zakieh mogą reprezentować dwie różne nazwy kobiet pochodzących z arabskiego pochodzenia, mianowicie arabski: زكية (zakiat), co oznacza \"czystość\", odpowiadające męskiej nazwie Zaki, i arabski: ذكيه (ḏakiyya), co oznacza\"inteligentny\". Zakija (Hebrajskie: זַכִּיָה), również śpiewany jako Zakiya, Zakija, Zakiyah lub Zakayah, jest hebrajskim nazwiskiem dla kobiet, które oznacza również \"czysty\".</p>", "Zarrina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zarina</b>.</p><p>Zarina jest nazwą żeńską pochodzącą od słowiańskiego słowa \"czar / tzar\" (царь), tytułu używanego przez sławskich monarchów lub najwyższych władców, a czasami także sufiksu (itsa), tytułu kobiety władcy autokratycznej (monarch) Bułgarii lub Rosji, lub tytułu żony czara. W starożytnej kulturze Sri Lanki bogini Zarina była powszechnie związana z bogiem podziemia, Harikesh.</p>", "Zulma": "<p>Zulma jest imieniem żeńskim, które pochodzi od sultanów Imperium Osmańskiego o imieniu Suleiman Wielki i niektórzy twierdzą, że pochodzi również od hebrajskiego \"shâlôm\", co oznacza \"pokój, pełność (w liczbie), bezpieczeństwo, zdrowie (w ciele), dobrobyt, zdrowie, dobrobyt , spokój, spokój, zadowolenie, przyjaźń, relacji międzyludzkich, zwłaszcza w związku z Bogiem w przymierzu\".</p>", "Zophia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Żywisława": "<b>Żywisława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/Neologizm\" target=\"_blank\" rel=\"noopener noreferrer\">neologizm</a> utworzony na wzór imion słowiańskich. Człon <i>Żywi-</i> jest niespotykany w staropolskich imionach dwuczłonowych.", "Zorana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zoran</b>.</p><b>Zoran</b> (<a href=\"https://pl.wikipedia.org/wiki/Cyrylica_serbska\" target=\"_blank\" rel=\"noopener noreferrer\">cyrylica serbska</a>: Зоран) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">południowosłowiańskie</a>, wywodzące się od słowa <i>zora</i> czyli „zorza, świt, jutrznia”.", "Zorica": "<p>Zorica (krylickie: Зорица) to kobiece imię. Znanymi osobami z nazwiska są: Zorica Dimitrijević-Stošić (1934-2013), serbska pianista, akompaniysta, pełnoprawny profesor fortepianu na Wydziale Muzyki w Belgradzie Zorica Ðurković (urodzona 1957), były piłkarz koszykówki Zorica Jevremović (urodzona 1948), dyrektor teatralny i wideo, dramaturg, choreograf Zorica Pantić (ur. około roku 1957).</p>", "Zytta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zyta</b>.</p><b>Zyta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od pospolitego <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a>&#160;<em>zitta</em>, z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>zita</em>, oznaczającego „dziewczynę”. Chrześcijańską patronką tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Zyta_z_Lukki\" target=\"_blank\" rel=\"noopener noreferrer\">Zyta z Lukki</a>, która jako jedyna wprowadziła to imię do kalendarzy. <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">Imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/27_kwietnia\" target=\"_blank\" rel=\"noopener noreferrer\">27 kwietnia</a>.", "Zynaida": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zinaida</b>.</p><b>Zenaida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (Ζηναΐς), oznaczające pierwotnie osobę poświęconą <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusowi</a>. Odnotowano dwie święte katolickie o tym imieniu, w tym <a href=\"https://pl.wikipedia.org/wiki/Zenaida_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">Zenaida z Tarsu</a> (męczennica, również święta <a href=\"https://pl.wikipedia.org/wiki/Prawos%C5%82awie\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławna</a>).", "Zbisława": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zbisław</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zbysław</b>.</p><b>Zbysław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z dwóch członów: <i>Zby-</i> („zbyć się, pozbyć się”) i <i>-sław</i>.", "Zofija": "<p>Sophia, również napisana Sofia, jest kobiece imię, z greckiego Σοφία, Sophía 'Mądrość'. Do innych form są Sophie, Sofiya, Sofija, Sophy, Sophea i Sofie.</p>", "Zofia Teresa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Zigrid": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zigrida</b>.</p><p>Sigrid to skandynawskie imię dla kobiet z starożytnego norweskiego Sigríðr, składające się z elementów sigr \"wygrę\" i fríðr \"piękna\". Powszechne krótkie formy obejmują Siri, Sigga, Sig i Sigi.</p>", "Zélie": "<p>Zélie to francuska skróta nazwiska Azélie. W Anglicznym pisowni i wymowach nazwy również używane są Zelie i Zellie.</p>", "Zakiya": "<p>Zakiya, Zakia, Zakiyah, Zakiyya lub Zakieh mogą reprezentować dwie różne nazwy kobiet pochodzących z arabskiego pochodzenia, mianowicie arabski: زكية (zakiat), co oznacza \"czystość\", odpowiadające męskiej nazwie Zaki, i arabski: ذكيه (ḏakiyya), co oznacza\"inteligentny\". Zakija (Hebrajskie: זַכִּיָה), również śpiewany jako Zakiya, Zakija, Zakiyah lub Zakayah, jest hebrajskim nazwiskiem dla kobiet, które oznacza również \"czysty\".</p>", "Zofia Antonina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Żanett": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Żanet</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Żaneta</b>.</p><b>Żaneta</b><b>, Żanetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a>, spolszczona forma imienia <i>Jeanette</i> (zdrobnienia od <i>Jeanne</i>, pol. <a href=\"https://pl.wikipedia.org/wiki/Janina\" target=\"_blank\" rel=\"noopener noreferrer\">Janina</a> lub <a href=\"https://pl.wikipedia.org/wiki/Joanna\" target=\"_blank\" rel=\"noopener noreferrer\">Joanna</a>).", "Zayna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zayn</b>.</p><p>Zayn Jawadd Malik (ang. Zain Javadd Malik; rodzaj.</p>", "Zulfija": "Urodziła się w rodzinie <a href=\"https://pl.wikipedia.org/wiki/%C5%BBydzi\" target=\"_blank\" rel=\"noopener noreferrer\">żydowskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Giser\" target=\"_blank\" rel=\"noopener noreferrer\">gisera</a>-chałupnika. Skończyła szkołę średnią i żeńską szkołę pedagogiczną, pracowała w redakcjach republikańskich gazet i pism, zaczęła pisać wiersze. W 1932, w wieku 17 lat, wydała swój pierwszy zbiór wierszy <i>Stranicy żyzni</i>, o młodzieży, przyjaźni i pięknie ludzkiej duszy. Od 1938 pracowała w różnych wydawnictwach, podczas <a href=\"https://pl.wikipedia.org/wiki/Front_wschodni_(II_wojna_%C5%9Bwiatowa)\" target=\"_blank\" rel=\"noopener noreferrer\">wojny ZSRR z Niemcami</a> pisała wiersze patriotyczne. W 1965 opublikowała zbiór wierszy <i>Kuylarim sizga</i> (<i>Śpiewam dla was</i>), a w 1971 poemat <i>Quyoshli qalam</i> (<i>Słoneczne pióro</i>). Pisała także artykuły prasowe o roli kobiety w rodzinie i społeczeństwie. Jej mężem był Hamid Olimjon, przewodniczący Związku Pisarzy Uzbekistanu. W Taszkencie jej imieniem nazwano ulicę, a w 2008 zbudowano jej pomnik. W 2004 ustanowiono Nagrodę Państwową im. Zulfiyi w dziedzinie literatury, sztuki, nauki, kultury i edukacji.", "Zümra": "<p>Zümra to tureckie imię żeńskie, które oznacza szmaragd. W 2021 roku znalazła się wśród dziesięciu najpopularniejszych nazw dla noworodków w Turcji.</p>", "Zarine": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zarin</b>.</p>Nazwa <a href=\"https://pl.wikipedia.org/wiki/Waluta\" target=\"_blank\" rel=\"noopener noreferrer\">waluty</a> w języku osetyjskim oznacza <a href=\"https://pl.wikipedia.org/wiki/Z%C5%82oto\" target=\"_blank\" rel=\"noopener noreferrer\">złoto</a> i nawiązuje do historycznych pieniędzy używanych na terytoriach starożytnej <a href=\"https://pl.wikipedia.org/wiki/Scytia\" target=\"_blank\" rel=\"noopener noreferrer\">Scytii</a>, <a href=\"https://pl.wikipedia.org/wiki/Sarmaci\" target=\"_blank\" rel=\"noopener noreferrer\">Sarmacji</a>, <a href=\"https://pl.wikipedia.org/wiki/Alanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Alanii</a> i <a href=\"https://pl.wikipedia.org/wiki/Osetia\" target=\"_blank\" rel=\"noopener noreferrer\">Osetii</a>.", "Zygrid": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zygrida</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zygryda</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zigrida</b>.</p><p>Sigrid to skandynawskie imię dla kobiet z starożytnego norweskiego Sigríðr, składające się z elementów sigr \"wygrę\" i fríðr \"piękna\". Powszechne krótkie formy obejmują Siri, Sigga, Sig i Sigi.</p>", "Żanneta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Żaneta</b>.</p><b>Żaneta</b><b>, Żanetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a>, spolszczona forma imienia <i>Jeanette</i> (zdrobnienia od <i>Jeanne</i>, pol. <a href=\"https://pl.wikipedia.org/wiki/Janina\" target=\"_blank\" rel=\"noopener noreferrer\">Janina</a> lub <a href=\"https://pl.wikipedia.org/wiki/Joanna\" target=\"_blank\" rel=\"noopener noreferrer\">Joanna</a>).", "Zdzislawa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zdzisław</b>.</p><b>Zdzisław</b>, <i><b>Zdziesław</b></i> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z dwóch członów: <i>Zdzie (Zdzi-)</i> (\"uczynić, zdziałać, zrobić\") i <i>-sław</i> (\"sława\"). Zanotowane w dokumentach z roku 1198.", "Zofia Elżbieta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Zarin": "Nazwa <a href=\"https://pl.wikipedia.org/wiki/Waluta\" target=\"_blank\" rel=\"noopener noreferrer\">waluty</a> w języku osetyjskim oznacza <a href=\"https://pl.wikipedia.org/wiki/Z%C5%82oto\" target=\"_blank\" rel=\"noopener noreferrer\">złoto</a> i nawiązuje do historycznych pieniędzy używanych na terytoriach starożytnej <a href=\"https://pl.wikipedia.org/wiki/Scytia\" target=\"_blank\" rel=\"noopener noreferrer\">Scytii</a>, <a href=\"https://pl.wikipedia.org/wiki/Sarmaci\" target=\"_blank\" rel=\"noopener noreferrer\">Sarmacji</a>, <a href=\"https://pl.wikipedia.org/wiki/Alanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Alanii</a> i <a href=\"https://pl.wikipedia.org/wiki/Osetia\" target=\"_blank\" rel=\"noopener noreferrer\">Osetii</a>.", "Ziemowita": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ziemowit</b>.</p><b>Ziemowit</b> – zniekształcona forma <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Siemowit_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Siemowit</a> oznaczającego „głowę rodu”.", "Zynoviia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zinoviia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zinovii</b>.</p><p>Zinovy lub Zinovi (rosyjski: Зиновий, romanizowany: Zinoviy; ukraiński: Зиновій, romanized: Zynoviy) to wschodnio-słowiańskie imię męskie pochodzące od Zenobios. Zmiany kobiece: rosyjski: Zinovia, ukraiński: Zynoviia (por.</p>", "Zohara": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zohar</b>.</p>Jest napisany po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejsku</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajsku</a>. Dzieło spisał prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/Moj%C5%BCesz_ben_Szem_Tow\" target=\"_blank\" rel=\"noopener noreferrer\">Mojżesz z Leonu</a>, ale zawiera ono także fragmenty wcześniejszego pochodzenia. Środowiska ortodoksyjne przypisują autorstwo Zoharu <a href=\"https://pl.wikipedia.org/wiki/Szymon_bar_Jochaj\" target=\"_blank\" rel=\"noopener noreferrer\">Szymonowi bar Jochajowi</a>, <a href=\"https://pl.wikipedia.org/wiki/Tannaici\" target=\"_blank\" rel=\"noopener noreferrer\">tanaicie</a> z II wieku. Poza komentarzami do wspomnianych ksiąg zawiera rozważania, interpretacje <a href=\"https://pl.wikipedia.org/wiki/Halacha\" target=\"_blank\" rel=\"noopener noreferrer\"><i>halachy</i></a>, traktaty o <a href=\"https://pl.wikipedia.org/wiki/Chiromancja\" target=\"_blank\" rel=\"noopener noreferrer\">chiromancji</a> i fragmenty filozoficzno-mistyczne. Do dziś pozostaje podstawowym tekstem żydowskiej <a href=\"https://pl.wikipedia.org/wiki/Mistycyzm\" target=\"_blank\" rel=\"noopener noreferrer\">mistyki</a> i <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej</a> <a href=\"https://pl.wikipedia.org/wiki/Kaba%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">kabały</a>. Poruszane są w nim zagadnienia natury <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Boga</a>, powstania i kształtu świata, natury <a href=\"https://pl.wikipedia.org/wiki/Dusza_(religia)\" target=\"_blank\" rel=\"noopener noreferrer\">duszy</a>, <a href=\"https://pl.wikipedia.org/wiki/Grzech\" target=\"_blank\" rel=\"noopener noreferrer\">grzechu</a>, <a href=\"https://pl.wikipedia.org/wiki/Zbawienie\" target=\"_blank\" rel=\"noopener noreferrer\">odkupienia</a>, <a href=\"https://pl.wikipedia.org/wiki/Dobro\" target=\"_blank\" rel=\"noopener noreferrer\">dobra</a> i <a href=\"https://pl.wikipedia.org/wiki/Z%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">zła</a> oraz pokrewne.", "Zahida": "<p>Zahida to kobiece imię arabskiego pochodzenia. Do wybitnych osób z tym nazwiskiem należą:</p>", "Zeenat": "<p>Zeenat, Zeenath lub Zinat to kobiece imię arabskiego pochodzenia. Może odnosić się do:</p>", "Zitta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zytta</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zyta</b>.</p><b>Zyta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od pospolitego <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a>&#160;<em>zitta</em>, z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>zita</em>, oznaczającego „dziewczynę”. Chrześcijańską patronką tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Zyta_z_Lukki\" target=\"_blank\" rel=\"noopener noreferrer\">Zyta z Lukki</a>, która jako jedyna wprowadziła to imię do kalendarzy. <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">Imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/27_kwietnia\" target=\"_blank\" rel=\"noopener noreferrer\">27 kwietnia</a>.", "Zynayda": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zinaida</b>.</p><b>Zenaida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (Ζηναΐς), oznaczające pierwotnie osobę poświęconą <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusowi</a>. Odnotowano dwie święte katolickie o tym imieniu, w tym <a href=\"https://pl.wikipedia.org/wiki/Zenaida_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">Zenaida z Tarsu</a> (męczennica, również święta <a href=\"https://pl.wikipedia.org/wiki/Prawos%C5%82awie\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławna</a>).", "Zinayda": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zinaida</b>.</p><b>Zenaida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (Ζηναΐς), oznaczające pierwotnie osobę poświęconą <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusowi</a>. Odnotowano dwie święte katolickie o tym imieniu, w tym <a href=\"https://pl.wikipedia.org/wiki/Zenaida_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">Zenaida z Tarsu</a> (męczennica, również święta <a href=\"https://pl.wikipedia.org/wiki/Prawos%C5%82awie\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławna</a>).", "Zaklin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Żaklina</b>.</p><b>Żaklina</b> – spolszczenie francuskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i>Jacqueline</i>, zapisane fonetycznie, które jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Jakub_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakub</a>. Jest również inny żeński odpowiednik tego imienia – <a href=\"https://pl.wikipedia.org/wiki/Jakubina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakubina</a>. Niektórzy błędnie uważają to imię za żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Jacek\" target=\"_blank\" rel=\"noopener noreferrer\">Jacek</a> (mylnie interpretując francuskie imię <i>Jacques</i>).", "Zofia Józefa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Zofia Krystyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Zwinisława": "<b>Zwnisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, składające się z członów <i>Zwni-</i> (prasłow. *<i>zvьněti</i> „brzmieć, dźwięczeć”, por. stpol. <i>zwonić</i>, współcz. <i>dzwonić</i> „wydawać dźwięk”) oraz <i>-sława</i> (por. <i>sława</i>, <i>sławić</i>).", "Zejneb": "<p>Zeineb lub Zejneb to bosniackie imię kobiety, transliteratowane z arabskiej nazwy Zaynab, i może odnosić się do: Zeineb Benzina, tunyjskiego archeologa</p>", "Zetta": "W <a href=\"https://pl.wikipedia.org/wiki/Informatyka\" target=\"_blank\" rel=\"noopener noreferrer\">informatyce</a> oznacza on częściej 2 = 1024 = 1 180 591 620 717 411 303 424, np. 1ZB (<a href=\"https://pl.wikipedia.org/wiki/Zettabajt\" target=\"_blank\" rel=\"noopener noreferrer\">zettabajt</a>) to 2 <a href=\"https://pl.wikipedia.org/wiki/Bajt\" target=\"_blank\" rel=\"noopener noreferrer\">bajtów</a>.", "Zeinabi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zeinab</b>.</p><p>Zaynab, i jego warianty, to arabskie imię dla kobiet, które oznacza \" kwiat w pustyni \". Zainab bint Muhammad była córką islamskiego proroka Muhammada, Zaynab bint Ali była wnuczką, dwie z jego żon były Zaynab binti Jahsh i Zaynab bin Khuzayma.</p>", "Zakiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zakia</b>.</p><p>Zakiya, Zakia, Zakiyah, Zakiyya lub Zakieh mogą reprezentować dwie różne nazwy kobiet pochodzących z arabskiego pochodzenia, mianowicie arabski: زكية (zakiat), co oznacza \"czystość\", odpowiadające męskiej nazwie Zaki, i arabski: ذكيه (ḏakiyya), co oznacza\"inteligentny\". Zakija (Hebrajskie: זַכִּיָה), również śpiewany jako Zakiya, Zakija, Zakiyah lub Zakayah, jest hebrajskim nazwiskiem dla kobiet, które oznacza również \"czysty\".</p>", "Zohreh": "<p>Zohreh (perskie: ناهید, arabski: الزهرة) to arabskie nazwisko kobiece, co oznacza \"Wenerę\".</p>", "Zwienisława": "<b>Zwnisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, składające się z członów <i>Zwni-</i> (prasłow. *<i>zvьněti</i> „brzmieć, dźwięczeć”, por. stpol. <i>zwonić</i>, współcz. <i>dzwonić</i> „wydawać dźwięk”) oraz <i>-sława</i> (por. <i>sława</i>, <i>sławić</i>).", "Zin": "<b>Zin</b>, <b>fanzin</b> (skrót od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>fan magazine</em>) – rodzaj nieprofesjonalnego pisma tworzonego przez osobę bądź grupę osób – miłośników jakiegoś tematu (np. <a href=\"https://pl.wikipedia.org/wiki/Muzyka\" target=\"_blank\" rel=\"noopener noreferrer\">muzyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Informatyka\" target=\"_blank\" rel=\"noopener noreferrer\">informatyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Literatura\" target=\"_blank\" rel=\"noopener noreferrer\">literatury</a>, <a href=\"https://pl.wikipedia.org/wiki/Fantastyka\" target=\"_blank\" rel=\"noopener noreferrer\">fantastyki</a>, <a href=\"https://pl.wikipedia.org/wiki/Gra_fabularna\" target=\"_blank\" rel=\"noopener noreferrer\">gier fabularnych</a>, <a href=\"https://pl.wikipedia.org/wiki/Ekologia\" target=\"_blank\" rel=\"noopener noreferrer\">ekologii</a>, <a href=\"https://pl.wikipedia.org/wiki/Polityka\" target=\"_blank\" rel=\"noopener noreferrer\">polityki</a>), skierowane do osób podzielających owe zainteresowania.", "Zaklina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Żaklin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Żaklina</b>.</p><b>Żaklina</b> – spolszczenie francuskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i>Jacqueline</i>, zapisane fonetycznie, które jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Jakub_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakub</a>. Jest również inny żeński odpowiednik tego imienia – <a href=\"https://pl.wikipedia.org/wiki/Jakubina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakubina</a>. Niektórzy błędnie uważają to imię za żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Jacek\" target=\"_blank\" rel=\"noopener noreferrer\">Jacek</a> (mylnie interpretując francuskie imię <i>Jacques</i>).", "Zahi̇de": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zahid</b>.</p><p>Zahid to męskie imię i nazwisko lub nazwisko, szczególnie popularne w kilku krajach Bliskiego Wschodu i Azji. Jego korzenie są w języku arabskim.</p>", "Zofia Helena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Zhanna-Yelyzaveta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zhanna</b>.</p><p>Zhanna to rosyjska forma imienia Jeanne. Znanymi osobami z tej nazwy są: Zhanna Agalakova (ur. 1965), rosyjska dziennikarz Zhanna Aguzarova (ur., 1962), sowiecka i rosyjska piosenkarka Zhanna Bichevskaya (ur. 1944), wybitna rosyjska barda i muzyka ludowa Zhanna Friske (1974-2015), rosyjskie aktorka filmowa, piosenkarz i socjaltynka Zhanna Pintusevich-Block (ur. 1972), biegacz, który uczestniczył w igrzyskach olimpijskich Zhanna Prokhorenko ...</p>", "Zulai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zula</b>.</p><b>Zuzanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שׁוֹשַׁנָּה&#8206; (<i>szoszana</i>), zapożyczonego przez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">język grecki</a>, a pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שׁוֹשָׁן&#8206; (<i>szoszan</i>), oznaczającego „lilia”, co z kolei prawdopodobnie wywodziło się od egipskiego <i>seszen</i>, czyli „lotos”. W Polsce imię to jest notowane w dokumentach od 1265 roku, w formach Zuzanna/Żużanna, a także pochodnych: Zanna/Żanna, Zanka/Zańka, Ożanka (zob. też <a href=\"https://pl.wikipedia.org/wiki/O%C5%BCanna_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Ożanna</a>), Zużka, Zuchna, Oszka. Wśród imion nadawanych nowo narodzonym dzieciom, Zuzanna w 2017 zajmowała 2. miejsce w grupie imion żeńskich.", "Zamzam": "<b>Zamzam, Zemzem</b> – święta studnia w <a href=\"https://pl.wikipedia.org/wiki/Mekka\" target=\"_blank\" rel=\"noopener noreferrer\">Mekce</a> w pobliżu świątyni <a href=\"https://pl.wikipedia.org/wiki/Al-Kaba\" target=\"_blank\" rel=\"noopener noreferrer\">Al-Kaba</a>; według tradycji powstała w czasach <a href=\"https://pl.wikipedia.org/wiki/Abraham\" target=\"_blank\" rel=\"noopener noreferrer\">Abrahama</a>. Tradycja mówi, że w jej miejscu w czasach proroka wytrysnęło źródło, gdy <a href=\"https://pl.wikipedia.org/wiki/Hagar_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Hagar</a> pozostawiona na pustyni z małym synem <a href=\"https://pl.wikipedia.org/wiki/Izmael\" target=\"_blank\" rel=\"noopener noreferrer\">Izmaelem</a> rozpaczliwie poszukiwała wody. Nazwa tego źródła wywodzi się od arabskiego słowa <i>zam</i> (<i>dość</i>), ponieważ, gdy woda tryskała z ziemi pod wysokim ciśnieniem, Hagar krzyczała właśnie „dość, dość”. Później studnia została zapomniana i zasypana. Ponownie odkrył ją dziadek <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a>, Abd al-Muttalib. Obecnie odwiedzana przez pielgrzymów muzułmańskich podczas <a href=\"https://pl.wikipedia.org/wiki/Had%C5%BCd%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">hadżdżu</a>. Picie wody z Zamzamu jest obyczajem religijnym zapewniającym zdrowie wiernego. Wodę z Zamzamu przechowuje się w specjalnych buteleczkach zwanych zamzamijja.", "Zoeya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zoey</b>.</p><p>Zoe to żeńskie imię pochodzenia greckiego, oznaczające \"życie\".</p>", "Zbigniewa Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zbigniewa</b>.</p><b>Zbygniewa</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Zbigniew\" target=\"_blank\" rel=\"noopener noreferrer\">Zbygniew</a>. Złożone jest z dwóch członów: <i>Zby-</i> (\"zbyć, zbyć się, pozbyć się\") i <i>-gniewa</i> (\"gniew\"). Oznacza prawdopodobnie \"tę, która się zbyła (pozbyła) gniewu\". Istnieje też tłumaczenie alternatywne: „miej zbytek (nadmiar) gniewu” (gniew – jako zapał wojenny – był uważany za cnotę).", "Zofia Eugenia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Zlatana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zlatan</b>.</p><b>Zlatan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a>&#160;Златан) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>. Popularne jest zwłaszcza wśród narodów <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie_po%C5%82udniowi\" target=\"_blank\" rel=\"noopener noreferrer\">południowosłowiańskich</a>; <a href=\"https://pl.wikipedia.org/wiki/Chorwaci\" target=\"_blank\" rel=\"noopener noreferrer\">Chorwatów</a>, <a href=\"https://pl.wikipedia.org/wiki/Serbowie\" target=\"_blank\" rel=\"noopener noreferrer\">Serbów</a>, <a href=\"https://pl.wikipedia.org/wiki/Boszniacy\" target=\"_blank\" rel=\"noopener noreferrer\">Boszniaków</a>, <a href=\"https://pl.wikipedia.org/wiki/Macedo%C5%84czycy\" target=\"_blank\" rel=\"noopener noreferrer\">Macedończyków</a>, <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garzy\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgarów</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owe%C5%84cy\" target=\"_blank\" rel=\"noopener noreferrer\">Sloweńców</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_po%C5%82udniowos%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">południowosłowiańskiego</a> słowa <i>zlato</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a>&#160;злато) oznaczającego w języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a> <i><a href=\"https://pl.wikipedia.org/wiki/Z%C5%82oto\" target=\"_blank\" rel=\"noopener noreferrer\">złoto</a></i>. Zdrobnienie imienia Zlatan to Zlatko, używane jest również jako samodzielne imię. Żeńskie formy tego imienia to <a href=\"https://pl.wikipedia.org/wiki/Zlata\" target=\"_blank\" rel=\"noopener noreferrer\">Zlata</a> i Zlatica.", "Żinaida": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zynayda</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zinaida</b>.</p><b>Zenaida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (Ζηναΐς), oznaczające pierwotnie osobę poświęconą <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusowi</a>. Odnotowano dwie święte katolickie o tym imieniu, w tym <a href=\"https://pl.wikipedia.org/wiki/Zenaida_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">Zenaida z Tarsu</a> (męczennica, również święta <a href=\"https://pl.wikipedia.org/wiki/Prawos%C5%82awie\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławna</a>).", "Zygmuntyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zygmunt</b>.</p><b>Zygmunt</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie oraz <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Składa się ze słów: <i>sigu</i> oznaczającego „zwycięstwo” i <i>mund</i> lub <i>munt</i>, „opieka”, „tarcza”. Można je zatem tłumaczyć jako „obrona przez zwycięstwo”.", "Ziemisława": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ziemisław</b>.</p><b>Siemisław</b>, <b>Siemosław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Siemo(i)-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*sěmьja</i> ma m.in. znaczenia „rodzina, ród; czeladź, służba, własność”) i <i>-sław</i> („sława”). Imię to wyraża życzenie sławy w przestrzeni rodzinnej.", "Zhanna-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zhanna</b>.</p><p>Zhanna to rosyjska forma imienia Jeanne. Znanymi osobami z tej nazwy są: Zhanna Agalakova (ur. 1965), rosyjska dziennikarz Zhanna Aguzarova (ur., 1962), sowiecka i rosyjska piosenkarka Zhanna Bichevskaya (ur. 1944), wybitna rosyjska barda i muzyka ludowa Zhanna Friske (1974-2015), rosyjskie aktorka filmowa, piosenkarz i socjaltynka Zhanna Pintusevich-Block (ur. 1972), biegacz, który uczestniczył w igrzyskach olimpijskich Zhanna Prokhorenko ...</p>", "Zbisława Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zbisława</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zbisław</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zbysław</b>.</p><b>Zbysław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z dwóch członów: <i>Zby-</i> („zbyć się, pozbyć się”) i <i>-sław</i>.", "Żanette": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Żanett</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Żanet</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Żaneta</b>.</p><b>Żaneta</b><b>, Żanetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a>, spolszczona forma imienia <i>Jeanette</i> (zdrobnienia od <i>Jeanne</i>, pol. <a href=\"https://pl.wikipedia.org/wiki/Janina\" target=\"_blank\" rel=\"noopener noreferrer\">Janina</a> lub <a href=\"https://pl.wikipedia.org/wiki/Joanna\" target=\"_blank\" rel=\"noopener noreferrer\">Joanna</a>).", "Zofia Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Zofia Jadwiga": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Zandra": "<p>Zandra to imię. Znanymi osobami z imieniem Zandra są: Zandra Ahl (urodzona 1975), szwedzka projektantka, artysta i autorka Zandra Borrero (urodzony 1973), kolumbijska sprinterka Zandra Flemister (1951-2023), amerykańska dyplomata i agentka Secret Service Zandra Flyg (urodzone 1988), szwedska kurlerka Zandra Mok (urodzono 1970), funkcjonariusz rządowy w Hongkongu Zandra Nowell (urodzonych 1936), brytyjska narciarka z gór gór górskich Zandra Pettersson (urodzena 1968), szwedy...</p>", "Zvezdana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zvezdan</b>.</p><p>Zvezdan (Serbski: Звездан) jest słowiańskim męskim imieniem. Do wybitnych osób z tym nazwiskiem należą: Zvezdan Čebinac (ur. 1939), były serbski były półoczniak i menedżer piłki nożnej Zvezdan Jovanović (ur. 1965), zabójca byłego premiera Serbii Zorana Đinđića w 2003 roku Zvezdan Martič, słoweński dziennikarz i inżynier Zvezdan Pejović (urat. 1966), emerytowany jugosławski obrońca piłki noży zawodowej Zvezdan Terzić...</p>", "Zofia Stanisława": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Zofia Małgorzata": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Zdzislava": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zdzisława</b>.</p><b>Zdzisława</b>, <i><b>Zdziesława</b></i> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Zdzis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Zdzisław</a>. Patronką tego imienia w Kościele katolickim jest bł. Zdzisława Czeska, patronka młodych małżeństw i matek.", "Zarife": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zarif</b>.</p><p>Zarif Davidson, najbardziej znana pod swoim mononimem Zarif Davidson (ang.</p>", "Zivar": "<p>Zivar (persk: زيور, również romanized jako Zīvar) jest nazwą powszechną w Iranie i Europie Wschodniej. Znaczenie nazwy \"Zivar\" to okładzenie klejnotów, złota lub srebra lub w ogóle biżuterii.</p>"};
